window.__BAUPASS_UI_BUILD = "20260528f";
window.__baupassEnterprise = { demoAllowed: null, copilotConfigured: null };

async function loadEnterpriseFlags() {
  try {
    const res = await fetch(`${API_BASE}/api/health`, { credentials: "include" });
    if (!res.ok) return;
    const data = await res.json();
    if (data.enterprise && typeof data.enterprise === "object") {
      window.__baupassEnterprise = data.enterprise;
    }
  } catch {
    // keep defaults
  }
}
const DEFAULT_RENDER_API_BASE = "https://baupass-production.up.railway.app";
const API_BASE_STORAGE_KEY = "baupass-api-base";
const LOCAL_API_BASE_FALLBACKS = [
  "http://127.0.0.1:8000",
  "http://localhost:8000",
  "https://127.0.0.1:8443",
  "https://localhost:8443",
];
// Only the canonical production API â old Railway hostnames cause CORS errors when tried as fallbacks.
const REMOTE_API_BASE_FALLBACKS = [
  DEFAULT_RENDER_API_BASE,
];

function normalizeApiBase(value) {
  return String(value || "").trim().replace(/\/+$/, "");
}

function sanitizeApiBase(value) {
  const normalized = normalizeApiBase(value);
  if (!normalized) {
    return "";
  }

  let parsed;
  try {
    parsed = new URL(normalized);
  } catch {
    return "";
  }

  // GitHub Pages laeuft ueber HTTPS; blockiere dort unsichere HTTP-Backends.
  if (window.location.protocol === "https:" && parsed.protocol === "http:") {
    const host = (parsed.hostname || "").toLowerCase();
    const localHosts = new Set(["localhost", "127.0.0.1", "::1"]);
    if (!localHosts.has(host)) {
      return "";
    }
  }

  return parsed.toString().replace(/\/+$/, "");
}

function resolveApiBase() {
  const params = new URL(window.location.href).searchParams;
  const queryValue = sanitizeApiBase(params.get("apiBase"));
  const metaValue = sanitizeApiBase(document.querySelector('meta[name="baupass-api-base"]')?.content);
  const onLocalHost = isLocalHostName(window.location.hostname);

  // Lokal immer same-origin â nie gespeicherte Production-URL (baupass-productionâĶ).
  if (onLocalHost) {
    if (!queryValue) {
      try {
        window.localStorage.removeItem(API_BASE_STORAGE_KEY);
      } catch {
        // ignore
      }
      return "";
    }
    window.localStorage.setItem(API_BASE_STORAGE_KEY, queryValue);
    return queryValue;
  }

  const rawStoredValue = sanitizeApiBase(window.localStorage.getItem(API_BASE_STORAGE_KEY));
  let storedValue = rawStoredValue;
  if (storedValue) {
    try {
      const storedHost = new URL(storedValue).hostname;
      if (isLocalHostName(storedHost)) {
        storedValue = "";
        window.localStorage.removeItem(API_BASE_STORAGE_KEY);
      }
    } catch {
      storedValue = "";
    }
  }
  const configuredValue = queryValue || metaValue || storedValue;

  if (configuredValue) {
    window.localStorage.setItem(API_BASE_STORAGE_KEY, configuredValue);
    return configuredValue;
  }

  if (!configuredValue && window.localStorage.getItem(API_BASE_STORAGE_KEY)) {
    window.localStorage.removeItem(API_BASE_STORAGE_KEY);
  }

  if (window.location.hostname.endsWith("github.io")) {
    return DEFAULT_RENDER_API_BASE;
  }

  return "";
}

let API_BASE = resolveApiBase();
const DEFAULT_BRAND_LOGO = API_BASE
  ? `${API_BASE}/branding/baukometra-logo.svg`
  : `${window.location.origin}/branding/baukometra-logo.svg`;
const SESSION_TOKEN_STORAGE_KEY = "baupass-control-token";
const SUPPORT_LOGIN_CONTEXT_KEY = "baupass-support-login-context";
const SUPPORT_PHONE_STORAGE_KEY = "baupass-support-phone";
const UI_LANG_STORAGE_KEY = "baupass-ui-lang";
const INVOICE_FILTERS_STORAGE_KEY = "baupass-invoice-filters-v1";
const UI_FALLBACK_LANG = "de";
const WORKER_PWA_BUILD_TAG = "20260525b";

function loadStoredSessionToken() {
  try {
    return (window.localStorage.getItem(SESSION_TOKEN_STORAGE_KEY) || "").trim();
  } catch {
    return "";
  }
}

function persistSessionToken(value) {
  try {
    const next = String(value || "").trim();
    if (next) {
      window.localStorage.setItem(SESSION_TOKEN_STORAGE_KEY, next);
    } else {
      window.localStorage.removeItem(SESSION_TOKEN_STORAGE_KEY);
    }
  } catch {
    // ignore storage failures (private mode / quota)
  }
}

function isLocalHostName(hostname) {
  const host = String(hostname || "").toLowerCase();
  return host === "localhost" || host === "127.0.0.1" || host === "::1";
}

function switchApiBaseForSession(nextBase) {
  const normalized = sanitizeApiBase(nextBase);
  if (!normalized || normalized === API_BASE) {
    return;
  }
  API_BASE = normalized;
  try {
    window.localStorage.setItem(API_BASE_STORAGE_KEY, normalized);
  } catch {
    // ignore storage failures
  }
}

function resolveLocalApiFallbackRequests(url) {
  const currentBase = sanitizeApiBase(API_BASE);
  let currentHost = "";
  if (currentBase) {
    try {
      currentHost = new URL(currentBase).hostname;
    } catch {
      currentHost = "";
    }
  }
  let parsedUrl;
  try {
    parsedUrl = new URL(String(url || ""), window.location.origin);
  } catch {
    return [];
  }
  const requestPath = `${parsedUrl.pathname}${parsedUrl.search}`;
  if (!requestPath.startsWith("/api/")) {
    return [];
  }

  const candidateBases = isLocalHostName(window.location.hostname)
    ? [...LOCAL_API_BASE_FALLBACKS, ...REMOTE_API_BASE_FALLBACKS]
    : [window.location.origin, ...REMOTE_API_BASE_FALLBACKS];

  const fallbackOrder = [...candidateBases].sort((a, b) => {
    const aHttps = a.startsWith("https://") ? 1 : 0;
    const bHttps = b.startsWith("https://") ? 1 : 0;
    // On local hosts, prefer plain HTTP dev servers first (usually :8000).
    if (isLocalHostName(window.location.hostname)) {
      return aHttps - bHttps;
    }
    return window.location.protocol === "https:" ? bHttps - aHttps : aHttps - bHttps;
  });

  const candidates = [];
  const seenBases = new Set();
  for (const candidateBaseRaw of fallbackOrder) {
    const candidateBase = sanitizeApiBase(candidateBaseRaw);
    if (!candidateBase || candidateBase === currentBase || seenBases.has(candidateBase)) {
      continue;
    }
    let parsedCandidate;
    try {
      parsedCandidate = new URL(candidateBase);
    } catch {
      continue;
    }
    // Avoid CSP violations on HTTPS pages by skipping HTTP fallbacks.
    if (window.location.protocol === "https:" && parsedCandidate.protocol !== "https:") {
      continue;
    }
    seenBases.add(candidateBase);
    candidates.push({
      base: candidateBase,
      url: `${candidateBase}${requestPath}`,
    });
  }
  return candidates;
}

function loadSupportLoginContext() {
  try {
    const url = new URL(window.location.href);
    const companyId = String(url.searchParams.get("supportCompanyId") || "").trim();
    if (companyId) {
      return {
        companyId,
        companyName: String(url.searchParams.get("supportCompanyName") || "").trim(),
        actorName: String(url.searchParams.get("supportActorName") || "").trim(),
      };
    }
  } catch {
    // ignore URL parsing failures
  }
  try {
    const raw = window.sessionStorage.getItem(SUPPORT_LOGIN_CONTEXT_KEY);
    if (!raw) {
      return null;
    }
    const parsed = JSON.parse(raw);
    if (!parsed || !parsed.companyId) {
      return null;
    }
    return {
      companyId: String(parsed.companyId || "").trim(),
      companyName: String(parsed.companyName || "").trim(),
      actorName: String(parsed.actorName || "").trim(),
    };
  } catch {
    return null;
  }
}

function persistSupportLoginContext(context) {
  try {
    if (!context?.companyId) {
      window.sessionStorage.removeItem(SUPPORT_LOGIN_CONTEXT_KEY);
      return;
    }
    window.sessionStorage.setItem(SUPPORT_LOGIN_CONTEXT_KEY, JSON.stringify({
      companyId: String(context.companyId || "").trim(),
      companyName: String(context.companyName || "").trim(),
      actorName: String(context.actorName || "").trim(),
    }));
  } catch {
    // ignore storage failures
  }
}

function clearSupportLoginContext() {
  try {
    window.sessionStorage.removeItem(SUPPORT_LOGIN_CONTEXT_KEY);
  } catch {
    // ignore storage failures
  }
}
