function getCurrentUser() {
  return state.currentUser;
}

function isSuperadminCompanyPreviewMode() {
  const role = String(getCurrentUser()?.role || "").toLowerCase();
  return role === "superadmin" && Boolean(String(superadminUiPreviewCompanyId || "").trim());
}

function getEffectiveUiRole() {
  if (isSuperadminCompanyPreviewMode()) {
    return "company-admin";
  }
  return String(getCurrentUser()?.role || "").toLowerCase();
}

function getEffectiveUiCompanyId() {
  if (isSuperadminCompanyPreviewMode()) {
    return String(superadminUiPreviewCompanyId || "").trim();
  }
  return String(getCurrentUser()?.company_id || getCurrentUser()?.companyId || "").trim();
}

function getCompanyPlan(companyId) {
  const normalizedCompanyId = String(companyId || "").trim();
  const company = state.companies.find((entry) => String(entry?.id || "").trim() === normalizedCompanyId);
  const rawPlan = String(company?.plan || "starter").trim().toLowerCase();
  return rawPlan in PLAN_RANK ? rawPlan : "starter";
}

function hasCompanyFeatureForCompanyId(companyId, featureKey) {
  const requiredPlan = PLAN_FEATURES[featureKey] || "enterprise";
  const resolvedCompanyId = String(companyId || getEffectiveUiCompanyId() || "").trim();
  const role = String(getCurrentUser()?.role || "").toLowerCase();
  if (!resolvedCompanyId) {
    return role === "superadmin";
  }
  const companyPlan = getCompanyPlan(resolvedCompanyId);
  return (PLAN_RANK[companyPlan] || 0) >= (PLAN_RANK[requiredPlan] || 3);
}

function hasCompanyFeature(featureKey) {
  return hasCompanyFeatureForCompanyId(getEffectiveUiCompanyId(), featureKey);
}

function getUiVisibleWorkers() {
  const companyId = getEffectiveUiCompanyId();
  if (!companyId) {
    return [...state.workers];
  }
  return state.workers.filter((entry) => String(entry?.companyId || entry?.company_id || "").trim() === companyId);
}

function getUiVisibleAccessLogs() {
  const workers = getUiVisibleWorkers();
  const allowedWorkerIds = new Set(workers.map((entry) => entry.id));
  return state.accessLogs.filter((entry) => allowedWorkerIds.has(entry.workerId));
}

function getUiVisibleLatestAccessEntries() {
  const workers = getUiVisibleWorkers();
  const allowedWorkerIds = new Set(workers.map((entry) => entry.id));
  return state.latestAccessEntries.filter((entry) => allowedWorkerIds.has(entry.workerId));
}

function getCurrentMonthKey() {
  const now = new Date();
  return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, "0")}`;
}

function normalizeMonthKey(value) {
  const raw = String(value || "").trim();
  return /^\d{4}-\d{2}$/.test(raw) ? raw : "";
}

function getRequestedWorkerHoursMonth() {
  const selected = normalizeMonthKey(elements.workerHoursMonthInput?.value);
  return selected || getCurrentMonthKey();
}

function formatHoursCompact(value) {
  const n = Number(value || 0);
  if (!Number.isFinite(n)) return "0";
  const normalized = Math.round(n * 100) / 100;
  return String(normalized).replace(/\.00$/, "").replace(/(\.\d)0$/, "$1").replace(".", ",");
}

async function loadAccessWorkerHoursMonth(monthOverride = "") {
  const companyId = getEffectiveUiCompanyId();
  const role = getEffectiveUiRole();
  const monthKey = normalizeMonthKey(monthOverride) || getRequestedWorkerHoursMonth();
  const roleCanSee = ["company-admin", "turnstile", "superadmin"].includes(role);

  if (!roleCanSee || !companyId || !hasCompanyFeatureForCompanyId(companyId, "worker_hours_report")) {
    state.accessHoursMonth = "";
    state.accessHoursCompanyId = "";
    state.accessHoursByWorker = {};
    return;
  }

  if (state.accessHoursMonth === monthKey && state.accessHoursCompanyId === companyId && Object.keys(state.accessHoursByWorker || {}).length > 0) {
    return;
  }

  try {
    const payload = await apiRequest(`${API_BASE}/api/companies/${companyId}/worker-hours-summary?month=${encodeURIComponent(monthKey)}`);
    const workers = Array.isArray(payload?.workers) ? payload.workers : [];
    const nextMap = {};
    workers.forEach((entry) => {
      const workerId = String(entry?.workerId || "").trim();
      if (!workerId) return;
      nextMap[workerId] = Number(entry?.totalHours || 0);
    });
    state.accessHoursMonth = monthKey;
    state.accessHoursCompanyId = companyId;
    state.accessHoursByWorker = nextMap;
  } catch {
    state.accessHoursByWorker = {};
  }
}

function setLatestAccessSnapshot(entries) {
  const normalizedEntries = (entries || []).map(normalizeLog)
    .filter((entry) => entry.workerId)
    .sort((left, right) => right.timestamp.localeCompare(left.timestamp));
  state.latestAccessEntries = normalizedEntries;
  state.latestAccessByWorker = Object.fromEntries(normalizedEntries.map((entry) => [entry.workerId, entry]));
}

function applyLatestAccessLogEntry(entry) {
  const normalizedEntry = normalizeLog(entry);
  if (!normalizedEntry.workerId) {
    return;
  }
  const nextEntries = [
    normalizedEntry,
    ...state.latestAccessEntries.filter((item) => item.workerId !== normalizedEntry.workerId)
  ].sort((left, right) => right.timestamp.localeCompare(left.timestamp));
  state.latestAccessEntries = nextEntries;
  state.latestAccessByWorker = {
    ...state.latestAccessByWorker,
    [normalizedEntry.workerId]: normalizedEntry
  };
}

function getLatestAccessForWorker(workerId) {
  if (!workerId) {
    return null;
  }
  return state.latestAccessByWorker[String(workerId)] || null;
}

function buildAccessLogsRequestConfig(options = {}) {
  const append = Boolean(options.append);
  const query = new URLSearchParams();
  const hasAccessFilters = Boolean(
    state.accessFilter.from
    || state.accessFilter.to
    || state.accessFilter.direction
    || state.accessFilter.gate
  );

  if (state.accessFilter.from) {
    query.set("from", state.accessFilter.from);
  }
  if (state.accessFilter.to) {
    query.set("to", state.accessFilter.to);
  }
  if (state.accessFilter.direction) {
    query.set("direction", state.accessFilter.direction);
  }
  if (state.accessFilter.gate) {
    query.set("gate", state.accessFilter.gate);
  }

  const limit = hasAccessFilters ? 5000 : 400;
  const offset = append ? state.accessLogs.length : 0;
  query.set("limit", String(limit));
  query.set("offset", String(offset));
  query.set("paginated", "1");

  return {
    hasAccessFilters,
    limit,
    offset,
    url: `${API_BASE}/api/access-logs?${query.toString()}`
  };
}

function normalizeAccessLogsResponse(payload, fallbackMeta = {}) {
  const items = Array.isArray(payload)
    ? payload
    : Array.isArray(payload?.items)
      ? payload.items
      : [];

  return {
    items: items.map(normalizeLog),
    meta: {
      limit: Number(payload?.limit || fallbackMeta.limit || 0),
      offset: Number(payload?.offset || fallbackMeta.offset || 0),
      hasMore: Boolean(payload?.hasMore),
      filtersApplied: Boolean(payload?.filtersApplied || fallbackMeta.filtersApplied)
    }
  };
}

async function loadMoreAccessLogs() {
  if (!state.accessLogsMeta?.hasMore) {
    return false;
  }

  const requestConfig = buildAccessLogsRequestConfig({ append: true });
  const payload = await apiRequest(requestConfig.url);
  const normalized = normalizeAccessLogsResponse(payload, requestConfig);
  const knownIds = new Set(state.accessLogs.map((entry) => entry.id));
  const additionalItems = normalized.items.filter((entry) => !knownIds.has(entry.id));

  if (!additionalItems.length) {
    state.accessLogsMeta = normalized.meta;
    return false;
  }

  state.accessLogs = [...state.accessLogs, ...additionalItems];
  state.accessLogsMeta = normalized.meta;
  return true;
}

function getDefaultViewForRole(role) {
  const normalized = String(role || "").toLowerCase();
  if (normalized === "turnstile") {
    return "access";
  }
  return "dashboard";
}

function canUseDeploymentPlan() {
  const role = String(getEffectiveUiRole() || "").toLowerCase();
  if (role === "turnstile") {
    return false;
  }
  if (role === "superadmin") {
    return true;
  }
  return (PLAN_RANK[getCompanyPlan(getEffectiveUiCompanyId())] || 0) >= PLAN_RANK.professional;
}

/** Einsatzplan-Editor lebt in Betrieb (admin-v2), wenn verfÃžgbar. */
function preferBetriebDeployment() {
  const role = String(getEffectiveUiRole() || "").toLowerCase();
  if (!["superadmin", "company-admin"].includes(role)) {
    return false;
  }
  return companyMeetsMinPlan(ADMIN_V2_EMBED_ITEM.minPlan || "starter");
}

function getAllowedViewsForRole(role) {
  const normalized = String(role || "").toLowerCase();
  let allowed = ["dashboard"];
  if (normalized === "superadmin") {
    allowed = ["dashboard", "workers", "badge", "access", "documents", "invoices", "admin", "devices"];
  }
  if (normalized === "company-admin") {
    allowed = ["dashboard", "workers", "badge", "access", "documents"];
    if (hasCompanyFeature("leave_management")) {
      allowed.push("leave");
    }
    if ((PLAN_RANK[getCompanyPlan(getEffectiveUiCompanyId())] || 0) >= PLAN_RANK.starter) {
      allowed.push("devices");
    }
  }
  if (normalized === "turnstile") {
    allowed = ["access", "documents", "dashboard"];
  }
  if (!hasCompanyFeature("document_upload")) {
    allowed = allowed.filter((entry) => entry !== "documents");
  }
  if (!hasCompanyFeature("invoicing")) {
    allowed = allowed.filter((entry) => entry !== "invoices");
  }
  if (normalized === "superadmin" || normalized === "company-admin") {
    const embedViews = getEnterpriseEmbedViews();
    allowed = [...new Set([...allowed, ...embedViews])];
  }
  if (canUseDeploymentPlan() && !preferBetriebDeployment()) {
    allowed.push("deployment-plan");
  }
  return [...new Set(allowed)];
}

function getEnterpriseEmbedViews() {
  const role = getEffectiveUiRole();
  if (role === "turnstile") {
    return [];
  }
  const views = ENTERPRISE_NAV_ITEMS.filter((item) => companyMeetsMinPlan(item.minPlan || "professional")).map(
    (item) => item.view,
  );
  if (companyMeetsMinPlan(ADMIN_V2_EMBED_ITEM.minPlan || "starter")) {
    views.push("admin-v2");
  }
  return [...new Set(views)];
}

const SIDEBAR_DRAWER_VIEWS = {
  navDrawerTeam: ["workers", "badge", "leave"],
  navDrawerCompliance: ["documents", "devices"],
  navDrawerAdmin: ["invoices", "admin"],
};

function syncSidebarDrawerOpenState(activeView) {
  const view = String(activeView || "").trim();
  document.querySelectorAll(".nav-drawer").forEach((drawer) => {
    drawer.removeAttribute("open");
  });
  for (const [drawerId, views] of Object.entries(SIDEBAR_DRAWER_VIEWS)) {
    if (views.includes(view)) {
      document.getElementById(drawerId)?.setAttribute("open", "");
      return;
    }
  }
  const platformViews = getEnterpriseEmbedViews();
  if (platformViews.includes(view)) {
    document.getElementById("navDrawerPlatform")?.setAttribute("open", "");
  }
}

function syncPlatformNavLinks() {
  const allowed = new Set(getAllowedViewsForRole(getEffectiveUiRole()));
  const activeView = getCurrentViewName();
  const betrieb = document.getElementById("navBetriebLink");
  if (betrieb) {
    const show = allowed.has("admin-v2");
    betrieb.classList.toggle("hidden", !show);
    betrieb.setAttribute("aria-hidden", show ? "false" : "true");
  }
  const hideLegacyDeployment = preferBetriebDeployment();
  document.querySelectorAll(".nav-link-deployment-plan, .quick-nav-tile[data-view='deployment-plan']").forEach((el) => {
    el.classList.toggle("hidden", hideLegacyDeployment);
    el.setAttribute("aria-hidden", hideLegacyDeployment ? "true" : "false");
  });
  document.querySelectorAll(".nav-link-betrieb").forEach((link) => {
    link.classList.toggle("active", activeView === "admin-v2");
  });
  document.querySelectorAll(".sidebar-nav .nav-link[data-view]").forEach((link) => {
    const view = link.dataset.view || "";
    const show = allowed.has(view);
    link.classList.toggle("hidden", !show);
    link.style.display = show ? "" : "none";
  });
  for (const [drawerId, views] of Object.entries(SIDEBAR_DRAWER_VIEWS)) {
    const drawer = document.getElementById(drawerId);
    if (!drawer) continue;
    const showDrawer = views.some((v) => allowed.has(v));
    drawer.classList.toggle("hidden", !showDrawer);
    drawer.setAttribute("aria-hidden", showDrawer ? "false" : "true");
  }
  const platformDrawer = document.getElementById("navDrawerPlatform");
  const enterpriseMount = document.getElementById("enterpriseNavMount");
  const showPlatform = Boolean(enterpriseMount?.querySelector(".nav-link[data-view]"));
  if (platformDrawer) {
    platformDrawer.classList.toggle("hidden", !showPlatform);
    platformDrawer.setAttribute("aria-hidden", showPlatform ? "false" : "true");
  }
  document.querySelectorAll(".dashboard-quick-nav .quick-nav-tile[data-view]").forEach((tile) => {
    const view = tile.dataset.view || "";
    const show = allowed.has(view);
    tile.classList.toggle("hidden", !show);
    tile.style.display = show ? "" : "none";
  });
  elements.navLinks = Array.from(document.querySelectorAll(".nav-link[data-view]"));
  syncSidebarDrawerOpenState(activeView);
}

function updateShellChrome(viewName) {
  const chrome = PLATFORM_VIEW_CHROME[viewName] || PLATFORM_VIEW_CHROME.dashboard;
  const eyebrowEl = document.getElementById("topbarEyebrowEl");
  const headingEl = document.getElementById("topbarHeadingEl");
  if (eyebrowEl) {
    eyebrowEl.textContent = uiT(chrome.eyebrow);
  }
  if (headingEl) {
    headingEl.textContent = uiT(chrome.heading);
  }
  document.body.dataset.activeView = viewName || "dashboard";
  const embedSection = document.querySelector(`[data-view="${viewName}"].view-embed`);
  const embedTitle = embedSection?.querySelector(".enterprise-embed-title");
  if (embedTitle) {
    embedTitle.textContent = uiT(chrome.eyebrow);
  }
}

function buildEnterpriseEmbedUrl(item) {
  if (!item?.path) {
    return "/";
  }
  const cid = getEffectiveUiCompanyId();
  let url = item.path;
  const params = [];
  if (item.embed) {
    params.push("embed=1");
  }
  if (item.version) {
    params.push("v=20260601prio1");
  }
  if (item.path.includes("/admin-v2/") && pendingAdminV2EinsatzplanFocus) {
    params.push("tab=workers");
    params.push("einsatzplan=1");
  }
  if (item.queryCompany && cid) {
    params.push(`company_id=${encodeURIComponent(cid)}`);
  }
  if (params.length) {
    url += `?${params.join("&")}`;
  }
  if (item.hash) {
    url += item.hash;
  }
  try {
    return new URL(url, window.location.origin).href;
  } catch {
    return url;
  }
}

function scheduleAdminV2EinsatzplanFocus() {
  const iframe = document.getElementById("adminV2Frame");
  if (!iframe) {
    return;
  }
  const workerId = pendingDeploymentOpenWorkerId;
  const workerName = pendingDeploymentOpenWorkerName;
  const send = () => {
    try {
      iframe.contentWindow?.postMessage(
        {
          type: "baupass-focus-einsatzplan",
          companyId: getEffectiveUiCompanyId(),
          workerId: workerId || undefined,
          workerName: workerName || undefined,
        },
        window.location.origin,
      );
    } catch {
      // iframe not ready
    }
  };
  send();
  iframe.addEventListener("load", send, { once: true });
  window.setTimeout(send, 500);
  window.setTimeout(send, 1500);
}

function broadcastSessionToEmbeds() {
  if (!token) {
    return;
  }
  const message = {
    type: "baupass-sync-token",
    token,
    companyId: getEffectiveUiCompanyId(),
  };
  Object.values(ENTERPRISE_EMBED_META).forEach((meta) => {
    const frame = document.getElementById(meta.frameId);
    try {
      frame?.contentWindow?.postMessage(message, window.location.origin);
    } catch {
      // iframe not ready
    }
  });
}

function requestEinsatzplanEditor(options = {}) {
  pendingDeploymentOpenWorkerId = String(options.workerId || "").trim() || null;
  pendingDeploymentOpenWorkerName = String(options.workerName || "").trim() || null;
  if (!token || !state.currentUser) {
    refreshAll();
    showToast(
      uiT("deploymentPlanLoginRequired") || "Bitte zuerst anmelden.",
      "error",
      8000,
    );
    focusLoginInput({ force: true });
    return;
  }
  const allowed = getAllowedViewsForRole(getEffectiveUiRole());
  if (!canUseDeploymentPlan()) {
    showToast(
      uiT("deploymentPlanLockedToast") || "Einsatzplan ist in Ihrem Paket nicht freigeschaltet (ab Professional).",
      "error",
      7000,
    );
    return;
  }
  if (allowed.includes("admin-v2")) {
    pendingAdminV2EinsatzplanFocus = true;
    pendingEnterpriseEmbedItemId = "admin-v2";
    setView("admin-v2");
    scheduleAdminV2EinsatzplanFocus();
    return;
  }
  if (allowed.includes("deployment-plan")) {
    setView("deployment-plan");
    broadcastSessionToEmbeds();
    const afterLoad = () => {
      const wid = pendingDeploymentOpenWorkerId;
      const wname = pendingDeploymentOpenWorkerName;
      pendingDeploymentOpenWorkerId = null;
      pendingDeploymentOpenWorkerName = null;
      if (wid && globalThis.BaupassDeploymentPlan?.openWorker) {
        globalThis.BaupassDeploymentPlan.openWorker(wid, wname || "");
        return;
      }
      globalThis.BaupassDeploymentPlan?.scrollToWorkers?.();
    };
    if (globalThis.BaupassDeploymentPlan?.refresh) {
      globalThis.BaupassDeploymentPlan.refresh().then(afterLoad).catch((err) => {
        showToast(err?.message || String(err), "error", 6000);
        afterLoad();
      });
    } else {
      window.setTimeout(afterLoad, 200);
    }
    return;
  }
  showToast(
    uiT("deploymentPlanLockedToast") || "Einsatzplan ist in Ihrem Paket nicht freigeschaltet (ab Professional).",
    "error",
    7000,
  );
}

function loadEnterpriseEmbed(viewName) {
  const meta = ENTERPRISE_EMBED_META[viewName];
  if (!meta) {
    return;
  }
  const itemId = pendingEnterpriseEmbedItemId || meta.defaultItemId;
  pendingEnterpriseEmbedItemId = null;
  const item =
    ENTERPRISE_NAV_ITEMS.find((entry) => entry.id === itemId) ||
    (viewName === "admin-v2" || itemId === "admin-v2" ? ADMIN_V2_EMBED_ITEM : null) ||
    ENTERPRISE_NAV_ITEMS.find((entry) => entry.view === viewName);
  if (!item) {
    return;
  }
  let url = buildEnterpriseEmbedUrl(item);
  if (viewName === "admin-v2" && pendingAdminV2EinsatzplanFocus) {
    try {
      const u = new URL(url, window.location.origin);
      u.searchParams.set("tab", "workers");
      u.searchParams.set("einsatzplan", "1");
      url = u.href;
    } catch {
      // keep buildEnterpriseEmbedUrl result
    }
  }
  const iframe = document.getElementById(meta.frameId);
  if (!iframe) {
    return;
  }
  const prevSrc = iframe.getAttribute("src") || "";
  const forceReload = viewName === "admin-v2" && pendingAdminV2EinsatzplanFocus;
  if (!prevSrc || prevSrc !== url || forceReload) {
    iframe.setAttribute("src", url);
  }
  globalThis.BaupassEmbed?.bindEnterpriseIframe?.(meta.frameId, {
    openUrl: url,
    title: uiT(item.labelKey) || viewName,
  });
  if (iframe && token) {
    const syncToken = () => {
      broadcastSessionToEmbeds();
      try {
        iframe.contentWindow?.postMessage(
          {
            type: "baupass-sync-token",
            token,
            companyId: getEffectiveUiCompanyId(),
          },
          window.location.origin,
        );
      } catch {
        // ignore cross-origin until loaded
      }
      if (viewName === "admin-v2" && pendingAdminV2EinsatzplanFocus) {
        scheduleAdminV2EinsatzplanFocus();
      }
    };
    iframe.addEventListener("load", syncToken, { once: false });
    syncToken();
  }
  if (viewName === "admin-v2" && pendingAdminV2EinsatzplanFocus) {
    scheduleAdminV2EinsatzplanFocus();
    pendingAdminV2EinsatzplanFocus = false;
  }
  const external = document.getElementById(meta.externalLinkId);
  if (external) {
    external.setAttribute("href", url);
  }
}

function getCurrentViewName() {
  const activeView = elements.views.find((view) => view.classList.contains("active"));
  return activeView?.dataset?.view || "dashboard";
}

function enforceRoleViewAccess() {
  const role = getEffectiveUiRole();
  const allowedViews = getAllowedViewsForRole(role);
  const currentView = getCurrentViewName();

  elements.navLinks.forEach((link) => {
    const viewName = link.dataset.view || "";
    const allowed = allowedViews.includes(viewName);
    link.style.display = allowed ? "" : "none";
  });

  // Hide sections that are only for superadmin (real role, not company preview)
  const isSuperadmin = String(getCurrentUser()?.role || "").toLowerCase() === "superadmin";
  document.querySelectorAll("[data-superadmin-only]").forEach((el) => {
    const show = isSuperadmin;
    el.hidden = !show;
    el.style.display = show ? "" : "none";
    el.setAttribute("aria-hidden", show ? "false" : "true");
  });

  if (!allowedViews.includes(currentView)) {
    setView(getDefaultViewForRole(role));
  }

  renderEnterpriseNavMenu();
}

function companyMeetsMinPlan(minPlan) {
  const role = getEffectiveUiRole();
  const cid = getEffectiveUiCompanyId();
  if (role === "superadmin" && !cid) {
    return true;
  }
  if (!cid && role !== "superadmin") {
    return false;
  }
  const plan = cid ? getCompanyPlan(cid) : "enterprise";
  const need = PLAN_RANK[minPlan] ?? PLAN_RANK.professional;
  return (PLAN_RANK[plan] ?? 0) >= need;
}

function renderEnterpriseNavMenu() {
  const mount = document.getElementById("enterpriseNavMount");
  if (!mount) {
    return;
  }
  const role = getEffectiveUiRole();
  if (role === "turnstile") {
    mount.innerHTML = "";
    mount.classList.add("hidden");
    return;
  }

  const cid = getEffectiveUiCompanyId();
  const seenViews = new Set();
  const items = ENTERPRISE_NAV_ITEMS.filter((item) => companyMeetsMinPlan(item.minPlan || "professional")).filter(
    (item) => {
      const viewKey = item.view || item.id;
      if (seenViews.has(viewKey)) {
        return false;
      }
      seenViews.add(viewKey);
      return true;
    },
  );

  syncPlatformNavLinks();

  if (!items.length) {
    mount.innerHTML = "";
    mount.classList.add("hidden");
    return;
  }

  mount.classList.remove("hidden");
  const planLabel = getPlanLabel(getCompanyPlan(cid));
  const sectionLabel = uiT("navEnterpriseSection");
  const planSuffix =
    planLabel && planLabel.toLowerCase() !== sectionLabel.toLowerCase()
      ? ` <span class="nav-plan-pill" title="${escapeHtml(sectionLabel)}">${escapeHtml(planLabel)}</span>`
      : "";
  let html = planSuffix ? `<p class="nav-enterprise-plan-hint muted small">${escapeHtml(sectionLabel)}${planSuffix}</p>` : "";
  items.forEach((item) => {
    const view = item.view || "";
    const embedItem = item.id !== view ? item.id : "";
    html += `<button type="button" class="nav-link nav-link-enterprise" data-view="${escapeHtml(view)}"${embedItem ? ` data-embed-item="${escapeHtml(embedItem)}"` : ""}>${escapeHtml(uiT(item.labelKey))}</button>`;
  });
  mount.innerHTML = html;
  ensureEnterpriseNavDelegation();
}

function ensureEnterpriseNavDelegation() {
  const mount = document.getElementById("enterpriseNavMount");
  if (!mount || enterpriseNavDelegationBound) {
    return;
  }
  mount.addEventListener("click", (event) => {
    const btn = event.target.closest("button[data-view]");
    if (!btn || !token) {
      return;
    }
    event.preventDefault();
    const embedItem = btn.getAttribute("data-embed-item");
    if (embedItem) {
      pendingEnterpriseEmbedItemId = embedItem;
    }
    setView(btn.dataset.view || "dashboard");
  });
  enterpriseNavDelegationBound = true;
}

function openEnterpriseView(viewName, embedItemId) {
  if (embedItemId) {
    pendingEnterpriseEmbedItemId = embedItemId;
  }
  setView(viewName);
}

let dashboardPollTimer = null;
let platformHealthPollTimer = null;
let _opsLiveFeedStop = null;

const PLATFORM_HEALTH_PROBE_LABELS = {
  api: "platformHealthProbeApi",
  ready: "platformHealthProbeReady",
  admin_v2: "platformHealthProbeAdminV2",
  enterprise_hub: "platformHealthProbeHub",
  ops_center: "platformHealthProbeOps",
};

function canViewPlatformHealth() {
  const role = String(getEffectiveUiRole() || "").toLowerCase();
  return role === "superadmin" || role === "company-admin";
}

function renderPlatformHealthPanel(payload, errorMessage) {
  const grid = document.getElementById("platformHealthGrid");
  const foot = document.getElementById("platformHealthFoot");
  const panel = document.getElementById("platformHealthPanel");
  if (!grid || !panel) return;
  if (!canViewPlatformHealth()) {
    panel.hidden = true;
    panel.setAttribute("aria-hidden", "true");
    return;
  }
  panel.hidden = false;
  panel.setAttribute("aria-hidden", "false");

  if (errorMessage) {
    grid.innerHTML = `<div class="platform-health-card is-fail" style="grid-column:1/-1">
      <p class="platform-health-label">${escapeHtml(uiT("platformHealthH3") || "Plattform")}</p>
      <p class="platform-health-value">${escapeHtml(uiT("platformHealthFail") || "Offline")}</p>
      <p class="platform-health-detail">${escapeHtml(errorMessage)}</p>
    </div>`;
    if (foot) foot.textContent = "";
    return;
  }

  const overall = String(payload?.status || "").toLowerCase();
  const overallCls =
    overall === "ok" ? "is-ok" : overall === "down" ? "is-fail" : "is-warn";
  const overallLabel =
    overall === "ok"
      ? uiT("platformHealthOk")
      : overall === "down"
        ? uiT("platformHealthFail")
        : uiT("platformHealthDegraded");

  const cards = [];
  cards.push(`
    <div class="platform-health-card ${overallCls}">
      <p class="platform-health-label">${escapeHtml(uiT("platformHealthEyebrow") || "Plattform")}</p>
      <p class="platform-health-value">${escapeHtml(overallLabel || overall)}</p>
      <p class="platform-health-detail">${escapeHtml(payload?.cloud?.provider || "")} Â· ${escapeHtml(payload?.cloud?.host || "")}</p>
    </div>`);

  const db = payload?.database || {};
  const dbOk = String(db.status || "").toLowerCase() === "ok";
  cards.push(`
    <div class="platform-health-card ${dbOk ? "is-ok" : "is-fail"}">
      <p class="platform-health-label">${escapeHtml(uiT("platformHealthProbeDb") || "Datenbank")}</p>
      <p class="platform-health-value">${dbOk ? escapeHtml(uiT("platformHealthOk") || "OK") : escapeHtml(uiT("platformHealthFail") || "Fail")}</p>
      <p class="platform-health-detail">${escapeHtml(String(db.backend || db.path || "").slice(0, 48))}</p>
    </div>`);

  (payload?.probes || []).forEach((probe) => {
    const key = String(probe.id || "");
    const labelKey = PLATFORM_HEALTH_PROBE_LABELS[key];
    const label = labelKey ? uiT(labelKey) : key;
    const ok = Boolean(probe.ok);
    cards.push(`
      <div class="platform-health-card ${ok ? "is-ok" : "is-fail"}">
        <p class="platform-health-label">${escapeHtml(label || key)}</p>
        <p class="platform-health-value">${ok ? escapeHtml(uiT("platformHealthOk") || "OK") : escapeHtml(uiT("platformHealthFail") || "Fail")}</p>
        <p class="platform-health-detail">${escapeHtml(probe.detail || "")}${probe.latencyMs != null ? ` Â· ${probe.latencyMs} ms` : ""}</p>
      </div>`);
  });

  grid.innerHTML = cards.join("");
  if (foot && payload) {
    const ts = payload.timestamp ? formatTimestamp(payload.timestamp) : "â";
    const url = payload.cloud?.publicUrl || window.location.origin;
    foot.textContent = (uiT("platformHealthFoot") || "Zuletzt: {time}")
      .replace("{time}", ts)
      .replace("{url}", url);
  }
}

async function refreshPlatformHealth() {
  if (!token || !canViewPlatformHealth()) return;
  const grid = document.getElementById("platformHealthGrid");
  if (grid) {
    grid.innerHTML = `<p class="muted">${escapeHtml(uiT("platformHealthLoading") || "PrÃžfeâĶ")}</p>`;
  }
  try {
    const data = await apiRequest(`${API_BASE}/api/health/platform`);
    renderPlatformHealthPanel(data);
  } catch (error) {
    renderPlatformHealthPanel(null, error?.message || String(error));
  }
}

function startPlatformHealthPoll() {
  if (platformHealthPollTimer || !canViewPlatformHealth()) return;
  void refreshPlatformHealth();
  platformHealthPollTimer = window.setInterval(() => {
    if (getCurrentViewName() !== "dashboard") {
      stopPlatformHealthPoll();
      return;
    }
    void refreshPlatformHealth();
  }, 90_000);
}

function stopPlatformHealthPoll() {
  if (platformHealthPollTimer) {
    window.clearInterval(platformHealthPollTimer);
    platformHealthPollTimer = null;
  }
}

function startOpsLiveFeed() {
  if (_opsLiveFeedStop || typeof window.BauPassOpsRealtime === "undefined") return;
  const feedEl = document.getElementById("liveEventsFeed");
  const modeTag = document.getElementById("liveEventsModeTag");
  if (!feedEl) return;
  const companyId = state.user?.company_id ? String(state.user.company_id) : "";
  window.BauPassOpsRealtime.start({
    companyId,
    feedEl,
    onMode(mode) {
      if (modeTag) modeTag.textContent = mode === "websocket" ? "â WebSocket" : "â SSE";
    },
    onEvent() {},
  }).then((stopFn) => {
    _opsLiveFeedStop = stopFn || null;
  }).catch(() => {});
}

function stopOpsLiveFeed() {
  if (_opsLiveFeedStop) {
    try { _opsLiveFeedStop(); } catch (_) {}
    _opsLiveFeedStop = null;
  }
  const feedEl = document.getElementById("liveEventsFeed");
  if (feedEl) feedEl.innerHTML = "<span class='muted small'>Nicht verbunden.</span>";
  const modeTag = document.getElementById("liveEventsModeTag");
  if (modeTag) modeTag.textContent = "";
}

function renderDeploymentDeclinesBannerEl(bannerEl, state) {
  if (!bannerEl) return;
  const count = Number(state?.declinedDayCount || 0);
  if (!count) {
    bannerEl.classList.add("hidden");
    bannerEl.innerHTML = "";
    return;
  }
  const items = (state.recentDeclines || [])
    .slice(0, 6)
    .map((item) => {
      const name = escapeHtml(String(item.workerName || item.workerId || "â"));
      const date = escapeHtml(String(item.workDate || "").slice(0, 10));
      const loc = escapeHtml(String(item.location || "â"));
      const reason = escapeHtml(String(item.reason || "").trim());
      return `<li><strong>${name}</strong> Â· ${date} Â· ${loc}${reason ? ` â ${reason}` : ""}</li>`;
    })
    .join("");
  bannerEl.innerHTML = `
    <div class="deployment-declines-banner-inner">
      <p class="deployment-declines-banner-title">${escapeHtml(uiT("deploymentDeclinesBannerTitle") || "Mitarbeiter haben Einsatztage abgelehnt")}</p>
      <p class="muted small">${escapeHtml(uiT("deploymentDeclinesBannerHint") || "")}</p>
      <ul class="deployment-declines-list">${items}</ul>
      <button type="button" class="primary-button small-button" data-view="deployment-plan">${escapeHtml(uiT("navDeploymentPlan") || "Einsatzplan")}</button>
    </div>`;
  bannerEl.classList.remove("hidden");
  bannerEl.querySelector("[data-view='deployment-plan']")?.addEventListener("click", () => setView("deployment-plan"));
}

async function refreshDashboardDeploymentDeclines() {
  const banner = document.getElementById("dashboardDeploymentDeclinesBanner");
  if (!banner || !token) return;
  const role = String(getCurrentUser()?.role || "").toLowerCase();
  if (!["company-admin", "superadmin"].includes(role)) {
    banner.classList.add("hidden");
    return;
  }
  if (role === "superadmin" && !getEffectiveUiCompanyId()) {
    banner.classList.add("hidden");
    return;
  }
  const now = new Date();
  const year = now.getFullYear();
  const month = now.getMonth() + 1;
  const q =
    role === "superadmin" && getEffectiveUiCompanyId()
      ? `?company_id=${encodeURIComponent(getEffectiveUiCompanyId())}`
      : "";
  try {
    const state = await apiRequest(
      `${API_BASE}/api/workforce/deployment-month${q}${q ? "&" : "?"}year=${year}&month=${month}`,
    );
    renderDeploymentDeclinesBannerEl(banner, state);
  } catch {
    banner.classList.add("hidden");
  }
}

function startDashboardPoll() {
  if (dashboardPollTimer) return;
  dashboardPollTimer = window.setInterval(async () => {
    if (getCurrentViewName() !== "dashboard") { stopDashboardPoll(); return; }
    try {
      const [latestRes, summaryRes] = await Promise.allSettled([
        apiRequest(`${API_BASE}/api/access-logs/latest?limit=20`),
        apiRequest(`${API_BASE}/api/access-logs/summary`),
      ]);
      if (latestRes.status === "fulfilled") {
        const items = Array.isArray(latestRes.value?.items) ? latestRes.value.items : [];
        setLatestAccessSnapshot(items);
      }
      if (summaryRes.status === "fulfilled") {
        state.accessInsights = summaryRes.value || state.accessInsights;
      }
      renderRecentAccess();
      renderStats();
      renderDashboardPorterLivePanel();
      void refreshDashboardDeploymentDeclines();
    } catch (_) { /* silent */ }
  }, 60_000);
}

function stopDashboardPoll() {
  if (dashboardPollTimer) { window.clearInterval(dashboardPollTimer); dashboardPollTimer = null; }
}

function setView(viewName) {
  if (viewName === "deployment-plan" && preferBetriebDeployment()) {
    requestEinsatzplanEditor();
    return;
  }
  const role = getEffectiveUiRole();
  const allowedViews = getAllowedViewsForRole(role);
  const targetView = allowedViews.includes(viewName) ? viewName : getDefaultViewForRole(role);

  elements.views.forEach((view) => {
    view.classList.toggle("active", view.dataset.view === targetView);
  });
  elements.navLinks.forEach((link) => {
    link.classList.toggle("active", link.dataset.view === targetView);
  });
  document.querySelectorAll("#enterpriseNavMount .nav-link").forEach((link) => {
    link.classList.toggle("active", link.dataset.view === targetView);
  });

  if (targetView === "invoices") {
    markCurrentInvoicesAsSeen();
    startInvoiceAutoRefresh();
    startInvoiceApprovalAutoRefresh();
  } else {
    stopInvoiceAutoRefresh();
    stopInvoiceApprovalAutoRefresh();
  }

  if (targetView === "dashboard") {
    startDashboardPoll();
    startPlatformHealthPoll();
    startOpsLiveFeed();
  } else {
    stopDashboardPoll();
    stopPlatformHealthPoll();
    stopOpsLiveFeed();
  }

  if (targetView === "devices") {
    loadDevices();
  }

  if (targetView === "documents") {
    loadDocumentInbox({ silent: true });
  }

  if (ENTERPRISE_EMBED_META[targetView]) {
    loadEnterpriseEmbed(targetView);
  }

  if (targetView === "deployment-plan" && globalThis.BaupassDeploymentPlan?.refresh) {
    globalThis.BaupassDeploymentPlan.refresh().catch((err) => {
      showToast(err?.message || String(err), "error", 6000);
    });
    globalThis.BaupassDeploymentPlan.startAutoRefresh?.();
  } else {
    globalThis.BaupassDeploymentPlan?.stopAutoRefresh?.();
  }

  if (targetView === "dashboard") {
    void refreshDashboardDeploymentDeclines();
  }

  document.querySelector(".content")?.classList.toggle("has-embed-view", Boolean(ENTERPRISE_EMBED_META[targetView]));
  updateShellChrome(targetView);
  syncPlatformNavLinks();
  scheduleHubUpgradeFocus(targetView);
}

function scheduleHubUpgradeFocus(targetView) {
  if (!pendingFocusBilling && !pendingFocusCompanies) {
    return;
  }
  const wantBilling = pendingFocusBilling && targetView === "invoices";
  const wantCompanies = pendingFocusCompanies && targetView === "admin";
  if (!wantBilling && !wantCompanies) {
    return;
  }
  requestAnimationFrame(() => {
    if (wantBilling) {
      pendingFocusBilling = false;
      void loadBillingOverview({ silent: true }).then(() => {
        document.getElementById("billingSubscriptionPortal")?.scrollIntoView({ behavior: "smooth", block: "start" });
        const plan = String(pendingHubUpgradePlan || "").trim().toLowerCase();
        pendingHubUpgradePlan = "";
        if (plan && state.billingOverview?.stripe?.configured) {
          void startBillingCheckout(plan, false);
        }
      });
    }
    if (wantCompanies) {
      pendingFocusCompanies = false;
      pendingHubUpgradePlan = "";
      document.getElementById("companyList")?.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  });
}

async function tryHubUpgradeCheckout(plan) {
  const normalized = String(plan || "").trim().toLowerCase();
  if (!normalized || !token) {
    return false;
  }
  if (!["starter", "professional", "enterprise", "tageskarte"].includes(normalized)) {
    return false;
  }
  try {
    await loadBillingOverview({ silent: true });
    if (!state.billingOverview?.stripe?.configured) {
      showToast(runtimeText("billingStripeUnavailable") || "Online-Zahlung ist gerade nicht verfÃžgbar.", "error", 7000);
      return false;
    }
    await startBillingCheckout(normalized, false);
    return true;
  } catch (error) {
    showToast(runtimeTextTemplate("billingCheckoutFailed", { error: error.message || String(error) }), "error", 8000);
    return false;
  }
}

function stopInvoiceAutoRefresh() {
  if (invoiceAutoRefreshTimer) {
    window.clearInterval(invoiceAutoRefreshTimer);
    invoiceAutoRefreshTimer = null;
  }
}

function stopInvoiceApprovalAutoRefresh() {
  if (invoiceApprovalRefreshTimer) {
    window.clearInterval(invoiceApprovalRefreshTimer);
    invoiceApprovalRefreshTimer = null;
  }
}

function markCurrentInvoicesAsSeen() {
  const seen = { ...(state.invoiceSeenIds || {}) };
  (state.invoices || []).forEach((invoice) => {
    if (invoice?.id) {
      seen[invoice.id] = true;
    }
  });
  state.invoiceSeenIds = seen;
  state.invoiceNewIds = {};
}

function getActiveInvoiceSearchQuery() {
  return String(document.querySelector("#invoiceFilterNumber")?.value || "").trim();
}

function startInvoiceAutoRefresh() {
  if (invoiceAutoRefreshTimer || getCurrentViewName() !== "invoices") {
    return;
  }
  invoiceAutoRefreshTimer = window.setInterval(async () => {
    if (!token || getCurrentViewName() !== "invoices") {
      stopInvoiceAutoRefresh();
      return;
    }
    await loadAndRenderInvoices({ silent: true, q: getActiveInvoiceSearchQuery() });
  }, 25000);
}

async function loadInvoiceApprovalsOnly(options = {}) {
  const { silent = true } = options;
  try {
    const approvalResponse = await apiRequest(API_BASE + "/api/invoices/approvals/pending");
    state.invoiceApprovalRequests = Array.isArray(approvalResponse) ? approvalResponse : [];
    renderInvoiceApprovalQueue();
  } catch (error) {
    if (!silent) {
      console.error("Failed to load invoice approvals:", error);
    }
  }
}

function startInvoiceApprovalAutoRefresh() {
  if (invoiceApprovalRefreshTimer || getCurrentViewName() !== "invoices") {
    return;
  }
  invoiceApprovalRefreshTimer = window.setInterval(async () => {
    if (!token || getCurrentViewName() !== "invoices") {
      stopInvoiceApprovalAutoRefresh();
      return;
    }
    await loadInvoiceApprovalsOnly({ silent: true });
  }, 20000);
}

function clearSession() {
  token = "";
  persistSessionToken("");
  state.currentUser = null;
  state.loginOtpPending = false;
  state.loginSetupEmailPending = false;
  state.companyAdminSecurity = {};
  state.companyTurnstiles = {};
  state.companyMailSettings = {};
}

function handleExpiredControlSession() {
  clearSession();
  refreshAll();
  const now = Date.now();
  if (sessionExpiryNoticeShown && (now - sessionExpiryNoticeAt) < 2500) {
    return;
  }
  sessionExpiryNoticeShown = true;
  sessionExpiryNoticeAt = now;
  showToast(uiT("alertSessionExpired"));
}

async function restoreSessionFromBootstrap() {
  const headers = { "Content-Type": "application/json" };
  if (token) {
    headers.Authorization = `Bearer ${token}`;
  }
  const response = await fetch(`${API_BASE}/api/session/bootstrap`, {
    method: "GET",
    headers,
    credentials: "include",
  });
  const bootstrap = await response.json().catch(() => ({}));
  if (
    !response.ok
    || bootstrap?.authenticated === false
    || ["unauthorized", "invalid_session", "session_expired"].includes(String(bootstrap?.error || ""))
  ) {
    clearSession();
    throw new Error("session_expired");
  }
  if (bootstrap?.token) {
    token = bootstrap.token;
    persistSessionToken(token);
  }
  if (bootstrap?.user) {
    state.currentUser = bootstrap.user;
    if (bootstrap.user.role === "superadmin") {
      let previewCid = String(bootstrap.user.preview_company_id || "").trim();
      if (!previewCid) {
        try {
          previewCid = String(localStorage.getItem("baupass-preview-company-id") || "").trim();
        } catch {
          // ignore
        }
      }
      if (previewCid) {
        superadminUiPreviewCompanyId = previewCid;
        const previewCompany = (state.companies || []).find((company) => company.id === superadminUiPreviewCompanyId);
        companyBrandingPreviewOverride = previewCompany ? getCompanyBrandingPreset(previewCompany) : "";
      }
    }
  }
  return bootstrap;
}

function startHeartbeat() {
  if (heartbeatTimer) {
    window.clearInterval(heartbeatTimer);
  }
  heartbeatTimer = window.setInterval(async () => {
    if (!token) return;
    try {
      const response = await fetch(`${API_BASE}/api/me/heartbeat`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        credentials: "include",
        body: JSON.stringify({}),
      });
      const payload = await response.json().catch(() => ({}));
      // Do not log users out on transient backend failures (502/503/network blips).
      // Logout only when backend explicitly confirms inactive/unauthorized session.
      if (response.status === 401 || payload?.active === false) {
        clearSession();
        refreshAll();
      }
    } catch {
      // heartbeat failures should not hard-crash UI
    }
  }, 4 * 60 * 1000);
}

function startBackendStatusMonitor() {
  if (backendStatusTimer) {
    window.clearInterval(backendStatusTimer);
  }
  backendStatusTimer = window.setInterval(async () => {
    try {
      await fetch(`${API_BASE}/api/health`, { credentials: "include" });
    } catch {
      // ignore transient offline checks
    }
  }, 30 * 1000);
}

async function apiRequest(url, options = {}) {
  const { method = "GET", body, auth = true, retries = 1 } = options;
  if (auth && !token) {
    handleExpiredControlSession();
    throw new Error("session_expired");
  }
  const normalizedMethod = String(method || "GET").toUpperCase();
  if (
    auth
    && isSupportReadOnlyMode()
    && !["GET", "HEAD", "OPTIONS"].includes(normalizedMethod)
    && !String(url || "").includes("/api/logout")
    && !String(url || "").includes("/api/me/heartbeat")
  ) {
    throw new Error("support_session_read_only");
  }
  const headers = { "Content-Type": "application/json", ...(options.headers || {}) };
  const requestToken = auth ? String(token || "") : "";
  if (auth && token) {
    headers.Authorization = `Bearer ${token}`;
  }

  let response;
  try {
    response = await fetch(url, {
      method,
      headers,
      credentials: "include",
      body: body === undefined ? undefined : JSON.stringify(body)
    });
  } catch {
    const fallbacks = resolveLocalApiFallbackRequests(url);
    if (!fallbacks.length) {
      throw new Error("backend_unreachable");
    }
    let fallbackSucceeded = false;
    for (const fallback of fallbacks) {
      try {
        response = await fetch(fallback.url, {
          method,
          headers,
          credentials: "include",
          body: body === undefined ? undefined : JSON.stringify(body)
        });
        switchApiBaseForSession(fallback.base);
        fallbackSucceeded = true;
        break;
      } catch {
        // try next candidate
      }
    }
    if (!fallbackSucceeded) {
      throw new Error("backend_unreachable");
    }
  }

  const payload = await response.json().catch(() => ({}));
  if (!response.ok) {
    if (payload?.error === "database_not_ready") {
      const requestError = new Error("database_not_ready");
      requestError.code = "database_not_ready";
      requestError.payload = payload;
      requestError.status = response.status;
      throw requestError;
    }
    if ([502, 503, 504].includes(Number(response.status))) {
      const fallbacks = resolveLocalApiFallbackRequests(url);
      for (const fallback of fallbacks) {
        try {
          const fallbackResponse = await fetch(fallback.url, {
            method,
            headers,
            credentials: "include",
            body: body === undefined ? undefined : JSON.stringify(body)
          });
          if (fallbackResponse.ok) {
            switchApiBaseForSession(fallback.base);
            return await fallbackResponse.json().catch(() => ({}));
          }
        } catch {
          // try next fallback
        }
      }
    }
    // ââ Retry bei 401 mit neuer Session ââ
    if (auth && response.status === 401 && retries > 0) {
      const currentToken = String(token || "");

      // Wenn sich das Token waehrend des Requests geaendert hat (z. B. Login in parallelem Tab),
      // direkt mit dem aktuellen Token erneut versuchen statt Bootstrap-Kaskade.
      if (requestToken && currentToken && requestToken !== currentToken) {
        return apiRequest(url, { ...options, retries: retries - 1 });
      }

      // Vermeidet Rekursion, falls der fehlgeschlagene Request bereits bootstrap selbst ist.
      if (!String(url || "").includes("/api/session/bootstrap")) {
        try {
          await restoreSessionFromBootstrap();
          if (token && state.currentUser) {
            return apiRequest(url, { ...options, retries: retries - 1 });
          }
        } catch {
          // Fallback zu Session-Ablauf
          handleExpiredControlSession();
          throw new Error("session_expired");
        }
      }
    }
    if (auth && ["invalid_session", "unauthorized"].includes(String(payload?.error || ""))) {
      handleExpiredControlSession();
      throw new Error("session_expired");
    }
    if (auth && ["company_locked", "company_paused", "company_trial_expired", "company_deleted", "company_not_found"].includes(String(payload?.error || ""))) {
      clearSession();
      refreshAll();
    }
    const requestError = new Error(payload?.error || `http_${response.status}`);
    requestError.code = payload?.error || `http_${response.status}`;
    requestError.payload = payload;
    requestError.status = response.status;
    throw requestError;
  }
  return payload;
}

function getDocumentInboxDisplayAddress() {
  const currentUser = getCurrentUser() || {};
  const role = String(currentUser.role || "");
  const currentCompanyId = String(currentUser.company_id || "");
  const settingsAddr = String(state.settings?.imapUsername || "").trim();
  if (role !== "company-admin") {
    return settingsAddr;
  }
  const company = (state.companies || []).find((entry) => String(entry?.id || "") === currentCompanyId);
  return String(company?.document_email || "").trim() || settingsAddr;
}

function updateDocumentEmailInfoBar() {
  const bar = document.querySelector("#docEmailInfoBar");
  const addr = document.querySelector("#docEmailInfoAddr");
  if (!bar || !addr) {
    return;
  }
  const displayAddress = getDocumentInboxDisplayAddress();
  if (!displayAddress) {
    bar.style.display = "none";
    addr.textContent = "";
    return;
  }
  addr.textContent = displayAddress;
  bar.style.display = "block";
}

function isDocumentInboxConfigured() {
  const host = String(state.settings?.imapHost || "").trim();
  const username = String(state.settings?.imapUsername || "").trim();
  const password = String(state.settings?.imapPassword || "").trim();
  const passwordConfigured = Boolean(state.settings?.imapPasswordConfigured) || Boolean(password);
  return Boolean(host && username && passwordConfigured);
}

function renderDocumentInboxList() {
  const container = document.querySelector("#docInboxList");
  if (!container) {
    return;
  }

  const currentRole = String(state.currentUser?.role || "").toLowerCase();
  const canReplyFromList = currentRole === "superadmin" || currentRole === "company-admin";

  const searchInput = document.querySelector("#docInboxSearchInput");
  const searchTerm = String(searchInput?.value || "").trim().toLowerCase();

  const allEntries = Array.isArray(state.documentInboxEntries) ? state.documentInboxEntries : [];
  const entries = searchTerm
    ? allEntries.filter((e) => {
        const hay = [e.from_addr || "", e.subject || "", e.matched_company_name || "", e.to_addr || ""].join(" ").toLowerCase();
        return hay.includes(searchTerm);
      })
    : allEntries;

  if (!allEntries.length) {
    container.innerHTML = `<div class="empty-state">${escapeHtml(uiT("docInboxEmpty"))}</div>`;
    return;
  }
  if (!entries.length) {
    container.innerHTML = `<div class="empty-state">Keine Ergebnisse f\u00fcr \u201e${escapeHtml(searchTerm)}\u201c</div>`;
    return;
  }

  const html = entries
    .map((entry) => {
      const attachments = Array.isArray(entry.attachments) ? entry.attachments : [];
      const attachmentsHtml = attachments.length
        ? attachments
          .map((att) => {
            const sizeBytes = Number(att?.file_size || 0);
            const sizeLabel = sizeBytes > 0
              ? `${Math.max(1, Math.round(sizeBytes / 1024))} KB`
              : "-";
            return `<li class="doc-inbox-attachment-item"><span>${escapeHtml(String(att?.filename || "Anhang"))}</span><span class="meta-text">${escapeHtml(sizeLabel)}</span></li>`;
          })
          .join("")
        : `<li class="doc-inbox-attachment-item"><span class="meta-text">-</span></li>`;

      const matchedCompany = String(entry?.matched_company_name || "").trim();
      const matchedCompanyMarkup = matchedCompany
        ? `<p class="meta-text">Firma: ${escapeHtml(matchedCompany)}</p>`
        : "";

      const isUnread = !entry.is_read;
      const unreadDot = isUnread ? `<span class="doc-inbox-unread-dot" title="Ungelesen"></span>` : "";

      return `
        <article class="card-item doc-inbox-item${isUnread ? " doc-inbox-unread" : ""}" data-open-inbox-id="${escapeHtml(String(entry?.id || ""))}" style="cursor:pointer;">
          <div class="doc-inbox-head">
            ${unreadDot}<strong style="${isUnread ? "font-weight:800;" : ""}">${escapeHtml(String(entry?.subject || "(ohne Betreff)"))}</strong>
            <span class="meta-text">${escapeHtml(formatTimestamp(entry?.received_at || ""))}</span>
          </div>
          <p class="helper-text">${escapeHtml(uiT("docInboxEmailFrom"))}: ${escapeHtml(String(entry?.from_addr || "-"))}</p>
          <p class="helper-text">An: ${escapeHtml(String(entry?.to_addr || "-"))}</p>
          ${matchedCompanyMarkup}
          <p class="meta-text">${escapeHtml(uiT("docInboxAttachments"))}: ${attachments.length || 0}</p>
          <div class="button-row doc-inbox-row-actions" style="margin-top:6px;">
            ${canReplyFromList ? `<button type="button" class="ghost-button small-button" data-reply-email-id="${escapeHtml(String(entry?.id || ""))}">${escapeHtml(runtimeText("docInboxReplySection"))}</button>` : ""}
            <button type="button" class="ghost-button small-button" data-dismiss-email-id="${escapeHtml(String(entry?.id || ""))}">${escapeHtml(uiT("btnDismissEmail"))}</button>
          </div>
        </article>
      `;
    })
    .join("");

  container.innerHTML = html;

  // Click on card â open detail modal
  container.querySelectorAll("[data-open-inbox-id]").forEach((card) => {
    card.addEventListener("click", async (event) => {
      // Don't open if they clicked action buttons
      if (event.target.closest("[data-dismiss-email-id]")) return;
      if (event.target.closest("[data-reply-email-id]")) return;
      const inboxId = String(card.dataset.openInboxId || "").trim();
      if (!inboxId) return;
      await openInboxMailDetail(inboxId, card);
    });
  });

  container.querySelectorAll("[data-reply-email-id]").forEach((button) => {
    button.addEventListener("click", async (event) => {
      event.stopPropagation();
      const inboxId = String(event.currentTarget.dataset.replyEmailId || "").trim();
      if (!inboxId) {
        return;
      }
      event.currentTarget.disabled = true;
      try {
        const card = event.currentTarget.closest("[data-open-inbox-id]");
        await openInboxMailDetail(inboxId, card);
        const replyBodyField = document.querySelector("#docInboxDetailModal #docInboxReplyBody");
        if (replyBodyField) {
          replyBodyField.focus();
        }
      } finally {
        event.currentTarget.disabled = false;
      }
    });
  });

  container.querySelectorAll("[data-dismiss-email-id]").forEach((button) => {
    button.addEventListener("click", async (event) => {
      event.stopPropagation();
      const inboxId = String(event.currentTarget.dataset.dismissEmailId || "").trim();
      if (!inboxId) {
        return;
      }
      event.currentTarget.disabled = true;
      try {
        await apiRequest(`${API_BASE}/api/documents/inbox/${inboxId}/dismiss`, {
          method: "POST",
          body: {}
        });
        await loadDocumentInbox({ silent: true });
      } catch (error) {
        showToast(uiT("alertGenericError").replace("{error}", error.message));
      } finally {
        event.currentTarget.disabled = false;
      }
    });
  });
}

async function openInboxMailDetail(inboxId, cardEl) {
  // Mark as read (also returns full entry with body_text)
  let entry = null;
  try {
    entry = await apiRequest(`${API_BASE}/api/documents/inbox/${inboxId}/mark-read`, { method: "POST", body: {} });
    // Remove unread styling from card
    if (cardEl) {
      cardEl.classList.remove("doc-inbox-unread");
      const dot = cardEl.querySelector(".doc-inbox-unread-dot");
      if (dot) dot.remove();
      const subj = cardEl.querySelector("strong");
      if (subj) subj.style.fontWeight = "";
    }
  } catch (err) {
    // Fallback: use existing entry from state
    entry = (state.documentInboxEntries || []).find((e) => e.id === inboxId) || null;
  }
  if (!entry) return;

  const DOC_TYPE_LABELS = {
    mindestlohnnachweis: "Mindestlohnnachweis",
    personalausweis: "Personalausweis",
    sozialversicherungsnachweis: "Sozialversicherungsnachweis",
    arbeitserlaubnis: "Arbeitserlaubnis",
    gesundheitszeugnis: "Gesundheitszeugnis",
    lohnabrechnung: "Lohnabrechnung",
    gehaltsabrechnung: "Gehaltsabrechnung",
    sonstiges: "Sonstiges",
  };

  // Filter workers by matched company if available
  const companyId = entry.matched_company_id || null;
  const availableWorkers = (state.workers || []).filter((w) =>
    !companyId || String(w.companyId || w.company_id || "") === String(companyId)
  );

  // Build or reuse modal
  let modal = document.getElementById("docInboxDetailModal");
  if (!modal) {
    modal = document.createElement("div");
    modal.id = "docInboxDetailModal";
    modal.style.cssText = "position:fixed;inset:0;z-index:8000;display:flex;align-items:center;justify-content:center;background:rgba(0,0,0,0.5);backdrop-filter:blur(4px);";
    document.body.appendChild(modal);
  }

  const renderModal = (currentAttachments) => {
    const attachments = Array.isArray(currentAttachments) ? currentAttachments : [];
    const bodyText = String(entry.body_text || "").trim();
    const role = String(state.currentUser?.role || "").toLowerCase();
    const canReply = role === "superadmin" || role === "company-admin";
    const rawSubject = String(entry.subject || "").trim() || String(runtimeText("docInboxNoSubject") || "(no subject)");
    const replySubject = /^re:/i.test(rawSubject) ? rawSubject : `Re: ${rawSubject}`;

    const attachmentsHtml = attachments.length
      ? attachments.map((att) => {
          const sizeKb = att.file_size > 0 ? `${Math.max(1, Math.round(att.file_size / 1024))} KB` : "";
          const isAssigned = !!(att.assigned_worker_id);
          const assignedWorker = isAssigned
            ? (state.workers || []).find((w) => w.id === att.assigned_worker_id)
            : null;
          const assignedName = assignedWorker
            ? `${assignedWorker.firstName || ""} ${assignedWorker.lastName || ""}`.trim()
            : att.assigned_worker_id || "";

          const workerOptions = availableWorkers.map((w) =>
            `<option value="${escapeHtml(w.id)}">${escapeHtml(`${w.firstName || ""} ${w.lastName || ""}`.trim() || w.id)}</option>`
          ).join("");

          const suggestedType = String(att.suggestedDocType || att.suggested_doc_type || "").trim();
          const suggestConf = String(att.suggestConfidence || att.suggest_confidence || "").trim();
          const docTypeOptions = Object.entries(DOC_TYPE_LABELS).map(([val, label]) =>
            `<option value="${escapeHtml(val)}"${suggestedType && val === suggestedType ? " selected" : ""}>${escapeHtml(label)}</option>`
          ).join("");
          const suggestReason = String(att.suggestReason || att.suggest_reason || "");
          const ocrLabel = suggestReason.startsWith("pdf_") ? " Â· PDF-Text" : "";
          const suggestHint = suggestedType && !isAssigned
            ? `<p class="helper-text" style="margin:4px 0 0;font-size:0.75em;color:var(--accent,#c78652);">Lohn-Erkennung: ${escapeHtml(DOC_TYPE_LABELS[suggestedType] || suggestedType)}${suggestConf === "high" ? " (hohe Sicherheit)" : ""}${ocrLabel}</p>`
            : "";

          return `<div class="doc-inbox-att-row" data-att-id="${escapeHtml(String(att.id || ""))}" style="padding:10px 0;border-bottom:1px solid var(--line,rgba(0,0,0,0.08));">
            <div style="display:flex;align-items:center;gap:8px;margin-bottom:6px;">
              <span style="font-size:1.2em;">ð</span>
              <div style="flex:1;min-width:0;">
                <div style="font-weight:600;font-size:0.88em;word-break:break-all;">${escapeHtml(att.filename || "Anhang")}</div>
                ${sizeKb ? `<div style="font-size:0.75em;color:var(--muted,#888);">${escapeHtml(sizeKb)}</div>` : ""}
              </div>
              ${isAssigned
                ? `<span style="font-size:0.75em;background:#d1fae5;color:#065f46;border-radius:20px;padding:2px 9px;white-space:nowrap;">â ${escapeHtml(assignedName)}</span>`
                : `<span style="font-size:0.75em;background:#fef3c7;color:#92400e;border-radius:20px;padding:2px 9px;white-space:nowrap;">${escapeHtml(runtimeText("notAssignedBadge"))}</span>`}
            </div>
            ${isAssigned ? "" : `
              <div class="doc-att-assign-form" style="display:flex;flex-wrap:wrap;gap:6px;align-items:center;margin-top:4px;">
                <select class="att-worker-select" style="flex:1;min-width:120px;font-size:0.82em;padding:5px 8px;border-radius:6px;border:1px solid var(--line,#ccc);background:var(--surface,#fff);color:var(--text,#1a1a1a);">
                  <option value="">${escapeHtml(runtimeText("docAssignWorkerPlaceholder"))}</option>
                  ${workerOptions}
                </select>
                <select class="att-doctype-select" style="flex:1;min-width:140px;font-size:0.82em;padding:5px 8px;border-radius:6px;border:1px solid var(--line,#ccc);background:var(--surface,#fff);color:var(--text,#1a1a1a);">
                  ${docTypeOptions}
                </select>
                <button type="button" class="att-assign-btn" style="font-size:0.82em;padding:5px 14px;border-radius:6px;background:var(--accent,#c78652);color:#fff;border:none;cursor:pointer;white-space:nowrap;">${escapeHtml(runtimeText("docAssignButton"))}</button>
              </div>
              ${suggestHint}
            `}
          </div>`;
        }).join("")
      : `<p style="color:var(--muted,#888);font-size:0.85em;">${escapeHtml(runtimeText("docNoAttachments"))}</p>`;

    modal.innerHTML = `
      <div style="background:var(--surface-strong,#fff);color:var(--text,#1a1a1a);border-radius:16px;box-shadow:0 8px 48px rgba(0,0,0,0.28);max-width:640px;width:95vw;max-height:88vh;display:flex;flex-direction:column;overflow:hidden;">
        <div style="padding:18px 20px 12px;border-bottom:1px solid var(--line,rgba(0,0,0,0.1));display:flex;justify-content:space-between;align-items:flex-start;gap:12px;">
          <div style="min-width:0;flex:1;">
            <div style="font-size:1.1em;font-weight:800;word-break:break-word;">${escapeHtml(String(entry.subject || "(ohne Betreff)"))}</div>
            <div style="font-size:0.8em;color:var(--muted,#666);margin-top:4px;">Von: <strong>${escapeHtml(String(entry.from_addr || "-"))}</strong></div>
            <div style="font-size:0.8em;color:var(--muted,#666);">An: ${escapeHtml(String(entry.to_addr || "-"))}</div>
            <div style="font-size:0.78em;color:var(--muted,#888);margin-top:2px;">${escapeHtml(formatTimestamp(entry.received_at || ""))}</div>
            ${entry.matched_company_name ? `<div style="font-size:0.8em;margin-top:4px;">ðĒ <strong>${escapeHtml(entry.matched_company_name)}</strong></div>` : ""}
          </div>
          <button id="docInboxDetailClose" style="background:none;border:none;font-size:1.6rem;cursor:pointer;color:var(--muted,#888);padding:0;line-height:1;flex-shrink:0;">Ã</button>
        </div>
        <div style="flex:1;overflow-y:auto;padding:16px 20px;display:flex;flex-direction:column;gap:16px;">
          <div>
            <div style="font-size:0.75em;font-weight:700;text-transform:uppercase;letter-spacing:0.06em;color:var(--muted,#888);margin-bottom:6px;">${escapeHtml(runtimeText("docInboxSectionMessage"))}</div>
            <div style="font-size:0.88em;white-space:pre-wrap;word-break:break-word;background:var(--surface,rgba(0,0,0,0.03));border-radius:8px;padding:12px;border:1px solid var(--line,rgba(0,0,0,0.07));">${escapeHtml(bodyText || "â")}</div>
          </div>
          ${attachments.length ? `<div>
            <div style="font-size:0.75em;font-weight:700;text-transform:uppercase;letter-spacing:0.06em;color:var(--muted,#888);margin-bottom:6px;">${escapeHtml(runtimeText("docInboxSectionAttachments"))} (${attachments.length})</div>
            ${attachmentsHtml}
          </div>` : ""}
          ${canReply ? `<div style="border-top:1px solid var(--line,rgba(0,0,0,0.08));padding-top:12px;">
            <div style="font-size:0.75em;font-weight:700;text-transform:uppercase;letter-spacing:0.06em;color:var(--muted,#888);margin-bottom:8px;">${escapeHtml(runtimeText("docInboxReplySection"))}</div>
            <label style="display:block;font-size:0.78em;color:var(--muted,#666);margin-bottom:4px;">${escapeHtml(runtimeText("docInboxReplySubjectLabel"))}</label>
            <input id="docInboxReplySubject" type="text" maxlength="240" value="${escapeHtml(replySubject)}" style="width:100%;box-sizing:border-box;padding:8px 10px;border-radius:8px;border:1px solid var(--line,#d1d5db);background:var(--surface,#fff);color:var(--text,#1a1a1a);margin-bottom:10px;" />
            <label style="display:block;font-size:0.78em;color:var(--muted,#666);margin-bottom:4px;">${escapeHtml(runtimeText("docInboxReplyBodyLabel"))}</label>
            <textarea id="docInboxReplyBody" rows="5" maxlength="8000" placeholder="${escapeHtml(runtimeText("docInboxReplyBodyPlaceholder"))}" style="width:100%;box-sizing:border-box;padding:10px;border-radius:8px;border:1px solid var(--line,#d1d5db);background:var(--surface,#fff);color:var(--text,#1a1a1a);resize:vertical;"></textarea>
            <div style="display:flex;justify-content:flex-end;margin-top:8px;">
              <button type="button" id="docInboxReplySendBtn" class="ghost-button small-button">${escapeHtml(runtimeText("docInboxReplySendButton"))}</button>
            </div>
          </div>` : ""}
        </div>
        <div style="padding:12px 20px;border-top:1px solid var(--line,rgba(0,0,0,0.1));display:flex;justify-content:flex-end;">
          <button id="docInboxDetailClose2" class="ghost-button small-button">${escapeHtml(runtimeText("docInboxCloseButton"))}</button>
        </div>
      </div>
    `;

    modal.style.display = "flex";
    const close = () => { modal.style.display = "none"; };
    modal.querySelector("#docInboxDetailClose").onclick = close;
    modal.querySelector("#docInboxDetailClose2").onclick = close;
    modal.addEventListener("click", (e) => { if (e.target === modal) close(); }, { once: true });

    // Wire up assign buttons
    modal.querySelectorAll(".att-assign-btn").forEach((btn) => {
      btn.addEventListener("click", async () => {
        const row = btn.closest(".doc-inbox-att-row");
        const attId = String(row?.dataset?.attId || "").trim();
        const workerId = row?.querySelector(".att-worker-select")?.value || "";
        const docType = row?.querySelector(".att-doctype-select")?.value || "";
        if (!workerId) { showToast(runtimeText("docAssignWorkerRequired")); return; }
        if (!docType) { showToast(runtimeText("docAssignDocTypeRequired")); return; }
        btn.disabled = true;
        btn.textContent = "âĶ";
        try {
          await apiRequest(
            `${API_BASE}/api/documents/inbox/${encodeURIComponent(inboxId)}/attachments/${encodeURIComponent(attId)}/assign`,
            { method: "POST", body: { workerId, docType } }
          );
          // Mark locally assigned and re-render
          const attObj = (Array.isArray(entry.attachments) ? entry.attachments : []).find((a) => a.id === attId);
          if (attObj) attObj.assigned_worker_id = workerId;
          renderModal(entry.attachments);
          await loadDocumentInbox({ silent: true });
        } catch (err) {
          btn.disabled = false;
          btn.textContent = runtimeText("docAssignButton");
          showToast(runtimeText("docAssignError").replace("{error}", err.message || String(err)));
        }
      });
    });

    const replyButton = modal.querySelector("#docInboxReplySendBtn");
    if (replyButton) {
      replyButton.addEventListener("click", async () => {
        const subjectField = modal.querySelector("#docInboxReplySubject");
        const bodyField = modal.querySelector("#docInboxReplyBody");
        const subject = String(subjectField?.value || "").trim();
        const body = String(bodyField?.value || "").trim();
        if (!body) {
          showToast(runtimeText("docInboxReplyBodyRequired"));
          bodyField?.focus();
          return;
        }
        replyButton.disabled = true;
        replyButton.textContent = "...";
        try {
          await apiRequest(`${API_BASE}/api/documents/inbox/${encodeURIComponent(inboxId)}/reply`, {
            method: "POST",
            body: { subject, body },
          });
          if (bodyField) {
            bodyField.value = "";
          }
          showToast(runtimeText("docInboxReplySuccess"));
        } catch (err) {
          showToast(runtimeText("docInboxReplyError").replace("{error}", err.message || String(err)));
        } finally {
          replyButton.disabled = false;
          replyButton.textContent = runtimeText("docInboxReplySendButton");
        }
      });
    }
  };

  renderModal(entry.attachments);
}


async function loadDocumentInbox(options = {}) {
  const { silent = false } = options;
  const container = document.querySelector("#docInboxList");
  if (container && !silent) {
    container.innerHTML = `<div class="empty-state">${escapeHtml(uiT("statusLoading"))}</div>`;
  }
  try {
    const payload = await apiRequest(`${API_BASE}/api/documents/inbox`);
    state.documentInboxEntries = Array.isArray(payload) ? payload : [];
    updateDocumentEmailInfoBar();
    renderDocumentInboxList();
    applySupportReadOnlyUiState();
  } catch (error) {
    state.documentInboxEntries = [];
    renderDocumentInboxList();
    if (!silent) {
      showToast(uiT("alertGenericError").replace("{error}", error.message));
    }
  }
}

async function triggerDocumentInboxSync(button) {
  if (!isDocumentInboxConfigured()) {
    showToast(runtimeText("imapNotConfigured"));
    return;
  }
  button.disabled = true;
  try {
    const payload = await apiRequest(`${API_BASE}/api/documents/imap/trigger`, {
      method: "POST",
      body: {}
    });
    const newCount = Number(payload?.imap?.newEmails || 0);
    await loadDocumentInbox({ silent: true });
    showToast(`Postfach abgerufen. Neue E-Mails: ${newCount}`);
  } catch (error) {
    showToast(uiT("alertGenericError").replace("{error}", error.message));
  } finally {
    button.disabled = false;
  }
}

async function rematchDocumentInboxLinks(button) {
  const isAllowed = getEffectiveUiRole() === "superadmin" && !isSupportReadOnlyMode() && !isSuperadminCompanyPreviewMode();
  if (!isAllowed) {
    showToast("Neu zuordnen ist nur fuer Superadmin erlaubt.");
    return;
  }
  button.disabled = true;
  try {
    const payload = await apiRequest(`${API_BASE}/api/documents/inbox/rematch-company-links`, {
      method: "POST",
      body: {}
    });
    const matched = Number(payload?.matchedCount || 0);
    await loadDocumentInbox({ silent: true });
    showToast(`Neu zugeordnet: ${matched}`);
  } catch (error) {
    const isForbidden = Number(error?.status || 0) === 403 || String(error?.code || error?.message || "").toLowerCase().includes("forbidden");
    if (isForbidden) {
      showToast("Neu zuordnen ist nur fuer Superadmin erlaubt.");
    } else {
      showToast(uiT("alertGenericError").replace("{error}", error.message));
    }
  } finally {
    button.disabled = false;
  }
}

function bindDocumentInboxControls() {
  const refreshButton = document.querySelector("#docInboxRefreshBtn");
  const syncButton = document.querySelector("#docInboxSyncBtn");
  const rematchButton = document.querySelector("#docInboxRematchBtn");
  const copyButton = document.querySelector("#docEmailCopyBtn");
  const searchInput = document.querySelector("#docInboxSearchInput");

  if (searchInput && !searchInput.dataset.bound) {
    searchInput.addEventListener("input", () => {
      renderDocumentInboxList();
    });
    searchInput.dataset.bound = "1";
  }

  if (refreshButton && !refreshButton.dataset.bound) {
    refreshButton.addEventListener("click", async () => {
      await loadDocumentInbox();
    });
    refreshButton.dataset.bound = "1";
  }

  if (syncButton && !syncButton.dataset.bound) {
    syncButton.addEventListener("click", async () => {
      await triggerDocumentInboxSync(syncButton);
    });
    syncButton.dataset.bound = "1";
  }

  if (rematchButton && !rematchButton.dataset.bound) {
    const isAllowed = getEffectiveUiRole() === "superadmin" && !isSupportReadOnlyMode() && !isSuperadminCompanyPreviewMode();
    rematchButton.disabled = !isAllowed;
    rematchButton.title = isAllowed ? "" : "Nur Superadmin";
    rematchButton.addEventListener("click", async () => {
      await rematchDocumentInboxLinks(rematchButton);
    });
    rematchButton.dataset.bound = "1";
  }

  const datevButton = document.querySelector("#docInboxDatevExportBtn");
  if (datevButton && !datevButton.dataset.bound) {
    datevButton.addEventListener("click", async () => {
      datevButton.disabled = true;
      try {
        await downloadPayrollDatevCsv();
        showToast("DATEV-CSV wurde heruntergeladen.");
      } catch (error) {
        showToast(uiT("alertGenericError").replace("{error}", error.message));
      } finally {
        datevButton.disabled = false;
      }
    });
    datevButton.dataset.bound = "1";
  }

  const datevConnectButton = document.querySelector("#docInboxDatevConnectBtn");
  if (datevConnectButton && !datevConnectButton.dataset.bound) {
    datevConnectButton.addEventListener("click", async () => {
      datevConnectButton.disabled = true;
      try {
        await startDatevOAuthConnect();
      } catch (error) {
        showToast(uiT("alertGenericError").replace("{error}", error.message));
      } finally {
        datevConnectButton.disabled = false;
      }
    });
    datevConnectButton.dataset.bound = "1";
  }

  if (copyButton && !copyButton.dataset.bound) {
    copyButton.addEventListener("click", async () => {
      const value = String(document.querySelector("#docEmailInfoAddr")?.textContent || "").trim();
      if (!value) {
        return;
      }
      try {
        await navigator.clipboard.writeText(value);
      } catch {
        window.prompt("E-Mail kopieren:", value);
      }
    });
    copyButton.dataset.bound = "1";
  }
}

function normalizeWorkerAppLink(rawLink) {
  const candidate = String(rawLink || "").trim();
  if (!candidate) {
    return "";
  }

  try {
    const normalized = new URL(candidate, window.location.origin);
    const workerApiBase = normalizeApiBase(API_BASE || window.location.origin);
    if (normalized.pathname.endsWith("/worker.html")) {
      // Access links should land on the install handoff page to avoid stale homescreen installs.
      if (normalized.searchParams.get("access")) {
        normalized.pathname = "/worker-install.html";
      }
      normalized.searchParams.set("v", WORKER_PWA_BUILD_TAG);
      normalized.searchParams.set("apiBase", workerApiBase);
    }
    if (normalized.pathname.endsWith("/worker-install.html")) {
      normalized.searchParams.set("v", WORKER_PWA_BUILD_TAG);
      normalized.searchParams.set("apiBase", workerApiBase);
    }
    return normalized.toString();
  } catch {
    return candidate;
  }
}

async function loadWorkerIdentityTokenStatuses(workersList) {
  const role = String(state.currentUser?.role || "").toLowerCase();
  if (!Array.isArray(workersList) || workersList.length === 0 || !["superadmin", "company-admin"].includes(role)) {
    state.identityTokenByWorker = {};
    return;
  }

  const requests = await Promise.allSettled(
    workersList.map((worker) => apiRequest(`${API_BASE}/api/workers/${worker.id}/identity-token`))
  );
  const nextState = {};
  workersList.forEach((worker, index) => {
    const result = requests[index];
    if (result?.status === "fulfilled") {
      const payload = result.value || {};
      nextState[worker.id] = {
        configured: Boolean(payload.configured),
        status: String(payload.status || "").toLowerCase(),
      };
      return;
    }
    nextState[worker.id] = {
      configured: false,
      status: "unknown",
    };
  });
  state.identityTokenByWorker = nextState;
}

async function loadAllData() {
  // Ohne gespeicherten Token gibt es keine Session zum Bootstrappen.
  // So vermeiden wir unnoetige 401-Requests im ausgeloggten Zustand.
  if (!token) {
    sessionExpiryNoticeShown = false;
    return;
  }

  // Bootstrap nur dann nutzen, wenn ein Token existiert, aber der User noch
  // nicht in den lokalen State geladen wurde.
  if (!state.currentUser) {
    let bootstrap;
    try {
      bootstrap = await restoreSessionFromBootstrap();
    } catch (error) {
      const msg = String(error?.message || "");
      console.warn("[Bootstrap] Failed:", msg);
      // Nicht eingeloggt ist beim ersten Laden ein normaler Zustand.
      if (["unauthorized", "invalid_session", "session_expired"].includes(msg)) {
        clearSession();
        sessionExpiryNoticeShown = false;
        return;
      }
      throw error;
    }
  }

  sessionExpiryNoticeShown = false;
  const gateOpsWindowMinutes = Math.max(5, Math.min(24 * 60, Number(state.gateOpsWindowMinutes || 60)));
  const accessLogsRequest = buildAccessLogsRequestConfig();
  const latestAccessUrl = `${API_BASE}/api/access-logs/latest`;

  const reportUrl = `${API_BASE}/api/reporting/summary`;
  const requests = await Promise.allSettled([
    apiRequest(`${API_BASE}/api/settings`),
    apiRequest(`${API_BASE}/api/companies`),
    apiRequest(`${API_BASE}/api/subcompanies`),
    apiRequest(`${API_BASE}/api/workers`),
    apiRequest(accessLogsRequest.url),
    apiRequest(latestAccessUrl),
    apiRequest(`${API_BASE}/api/invoices`),
    apiRequest(`${API_BASE}/api/access-logs/summary`),
    apiRequest(`${API_BASE}/api/access-logs/day-close-check`),
    apiRequest(`${API_BASE}/api/audit-logs?eventType=company.repair&targetType=company&limit=120`),
    apiRequest(reportUrl),
    apiRequest(`${API_BASE}/api/compliance/overview`),
    apiRequest(`${API_BASE}/api/compliance/expiring-docs?days=30&limit=150`),
    apiRequest(`${API_BASE}/api/audit-logs?limit=200`),
    apiRequest(`${API_BASE}/api/gates/ops-metrics?windowMinutes=${gateOpsWindowMinutes}`),
    apiRequest(`${API_BASE}/api/operations/snapshot`)
  ]);

  const [settings, companies, subcompanies, workers, accessLogs, latestAccess, invoices, summary, dayClose, repairAudit, reporting, complianceOverview, complianceExpiringDocs, auditLogs, gateOpsMetrics, operationsSnapshot] = requests;
  if (settings.status === "fulfilled") {
    state.settings = settings.value || state.settings;
    document.dispatchEvent(new CustomEvent("baupass:settingsLoaded"));
  }
  if (companies.status === "fulfilled") {
    state.companies = companies.value || [];
    // Branding-Override nach Laden der Unternehmen auflÃķsen (bei wiederhergestellter Vorschau-Session)
    if (superadminUiPreviewCompanyId && !companyBrandingPreviewOverride) {
      const previewCompany = state.companies.find((c) => c.id === superadminUiPreviewCompanyId);
      if (previewCompany) {
        companyBrandingPreviewOverride = getCompanyBrandingPreset(previewCompany);
      }
    }
  }
  if (subcompanies.status === "fulfilled") state.subcompanies = subcompanies.value || [];
  if (workers.status === "fulfilled") {
    state.workers = workers.value || [];
    await loadWorkerIdentityTokenStatuses(state.workers);
  }
  await loadAccessWorkerHoursMonth();
  if (accessLogs.status === "fulfilled") {
    const normalizedAccessLogs = normalizeAccessLogsResponse(accessLogs.value, accessLogsRequest);
    state.accessLogs = normalizedAccessLogs.items;
    state.accessLogsMeta = normalizedAccessLogs.meta;
  }
  if (latestAccess.status === "fulfilled") {
    const latestAccessItems = Array.isArray(latestAccess.value?.items) ? latestAccess.value.items : [];
    setLatestAccessSnapshot(latestAccessItems);
  }
  if (invoices.status === "fulfilled") state.invoices = invoices.value || [];
  if (invoices.status !== "fulfilled") state.invoices = [];
  if (summary.status === "fulfilled") state.accessInsights = summary.value || state.accessInsights;
  if (reporting.status === "fulfilled") state.reporting = reporting.value || state.reporting;
  if (dayClose.status === "fulfilled") state.dayClose = dayClose.value || null;
  if (repairAudit.status === "fulfilled") {
    const grouped = {};
    ((repairAudit.value && Array.isArray(repairAudit.value.logs) ? repairAudit.value.logs : repairAudit.value) || []).forEach((entry) => {
      const companyId = entry?.target_id || "";
      if (!companyId) {
        return;
      }
      if (!grouped[companyId]) {
        grouped[companyId] = [];
      }
      grouped[companyId].push(entry);
    });
    Object.keys(grouped).forEach((companyId) => {
      grouped[companyId] = grouped[companyId].slice(0, 5);
    });
    state.companyRepairHistory = grouped;
  } else {
    state.companyRepairHistory = {};
  }

  if (complianceOverview.status === "fulfilled") {
    state.complianceOverview = Array.isArray(complianceOverview.value) ? complianceOverview.value : [];
  } else {
    state.complianceOverview = [];
  }

  if (complianceExpiringDocs.status === "fulfilled") {
    state.complianceExpiringDocs = Array.isArray(complianceExpiringDocs.value?.items) ? complianceExpiringDocs.value.items : [];
    state.expiringDocsCriticalCount = state.complianceExpiringDocs.filter(
      (item) => Number(item?.daysLeft) <= 7 || item?.urgency === "critical"
    ).length;
  } else {
    state.complianceExpiringDocs = [];
    state.expiringDocsCriticalCount = 0;
  }
  state.auditLogPageSize = 50;

  if (auditLogs.status === "fulfilled") {
    state.auditLogs = Array.isArray(auditLogs.value?.logs) ? auditLogs.value.logs : [];
  } else {
    state.auditLogs = [];
  }

  if (operationsSnapshot.status === "fulfilled") {
    state.operationsSnapshot = operationsSnapshot.value || null;
  } else {
    state.operationsSnapshot = null;
  }

  if (gateOpsMetrics.status === "fulfilled") {
    state.gateOpsMetrics = gateOpsMetrics.value || state.gateOpsMetrics;
  } else {
    state.gateOpsMetrics = {
      windowMinutes: 60,
      sampleSize: 0,
      avgMs: 0,
      p50Ms: 0,
      p95Ms: 0,
      p99Ms: 0,
      outcomes: {},
      slowest: [],
    };
  }

  state.companyTurnstiles = {};
  state.companyAdminSecurity = {};
  state.companyMailSettings = {};
  if (companies.status === "fulfilled" && ["superadmin", "company-admin"].includes(String(state.currentUser?.role || ""))) {
    const visibleCompanies = (companies.value || []).filter((company) => !company.deleted_at);
    const [turnstileRequests, securityRequests, companyMailRequests] = await Promise.all([
      Promise.allSettled(
        visibleCompanies.map((company) => apiRequest(`${API_BASE}/api/companies/${company.id}/turnstiles`))
      ),
      state.currentUser?.role === "superadmin"
        ? Promise.allSettled(
            visibleCompanies.map((company) => apiRequest(`${API_BASE}/api/companies/${company.id}/admin-security`))
          )
        : Promise.resolve(visibleCompanies.map(() => ({ status: "skipped" }))),
      Promise.allSettled(
        visibleCompanies.map((company) => apiRequest(`${API_BASE}/api/companies/${company.id}/mail-settings`))
      ),
    ]);
    visibleCompanies.forEach((company, index) => {
      const result = turnstileRequests[index];
      state.companyTurnstiles[company.id] = result?.status === "fulfilled" && Array.isArray(result.value)
        ? result.value
        : [];

      const mailResult = companyMailRequests[index];
      state.companyMailSettings[company.id] = mailResult?.status === "fulfilled" && mailResult.value
        ? mailResult.value
        : {
            companyId: company.id,
            mailProvider: "gmail",
            imapHost: "imap.gmail.com",
            imapPort: 993,
            imapUsername: "",
            imapUseTls: true,
            smtpHost: "smtp.gmail.com",
            smtpPort: 587,
            smtpUsername: "",
            smtpUseTls: true,
            senderEmail: "",
            senderName: "",
            imapPasswordConfigured: false,
            smtpPasswordConfigured: false,
            brevoApiKeyConfigured: false,
            testInboundStatus: "pending",
            testOutboundStatus: "pending",
            lastTestInbound: "",
            lastTestOutbound: "",
          };

      if (state.currentUser?.role === "superadmin") {
        const sec = securityRequests[index];
        state.companyAdminSecurity[company.id] = sec?.status === "fulfilled" ? sec.value : null;
      }
    });
  }
}

function refreshAll() {
  const loggedIn = Boolean(token && state.currentUser);
  syncSupportLoginUi();
  if (elements.authOverlay) {
    const activeElement = document.activeElement;
    if (loggedIn && activeElement && elements.authOverlay.contains(activeElement) && typeof activeElement.blur === "function") {
      activeElement.blur();
    }
    elements.authOverlay.classList.toggle("active", !loggedIn);
    elements.authOverlay.setAttribute("aria-hidden", loggedIn ? "true" : "false");
    elements.authOverlay.toggleAttribute("inert", loggedIn);
  }
  if (elements.mainShell) {
    elements.mainShell.style.display = loggedIn ? "grid" : "none";
    elements.mainShell.classList.toggle("locked", !loggedIn);
    elements.mainShell.hidden = !loggedIn;
    elements.mainShell.setAttribute("aria-hidden", loggedIn ? "false" : "true");
    elements.mainShell.toggleAttribute("inert", !loggedIn);
  }
  if (elements.body) {
    elements.body.classList.toggle("auth-locked", !loggedIn);
    if (!loggedIn) {
      companyBrandingPreviewOverride = "";
      superadminUiPreviewCompanyId = "";
      elements.body.setAttribute("data-branding-preset", "construction");
    }
  }

  if (!loggedIn) {
    focusLoginInput();
  }

  updateTopbarActionsState(loggedIn);
  renderSuperadminPreviewTopbar(loggedIn);
  renderSuperadminSimulationBar(loggedIn);
  renderSuperadminPreviewSidebarStatus(loggedIn);
  renderSuperadminSidebarCompanyPicker(loggedIn);
  renderSystemAlertBanner(loggedIn);
  renderSupportReadOnlyTopbarBadge(loggedIn);

  if (loggedIn && elements.sessionCard) {
    const texts = getRuntimeUiTexts();
    const actualRole = String(state.currentUser?.role || "").toLowerCase();
    const role = getRoleLabel(
      isSuperadminCompanyPreviewMode() ? `${actualRole} â ${getRoleLabel("company-admin")}` : actualRole,
    );
    const user = state.currentUser?.username || "-";
    const supportModeMarkup = isSupportReadOnlyMode()
      ? `<br /><strong>${escapeHtml(uiT("supportModeLabel"))}</strong> ${escapeHtml(uiT("supportReadOnlyFor"))} ${escapeHtml(state.currentUser?.support_company_name || uiT("supportCompanyFallback"))}${state.currentUser?.support_actor_name ? ` | ${escapeHtml(uiT("supportStartedBy"))} ${escapeHtml(state.currentUser.support_actor_name)}` : ""}`
      : "";
    const previewCompany = state.companies.find((entry) => String(entry?.id || "") === String(superadminUiPreviewCompanyId || ""));
    const previewMarkup = isSuperadminCompanyPreviewMode() && previewCompany
      ? `<br /><strong>${escapeHtml(runtimeText("companyBrandingPreviewLabel"))}:</strong> ${escapeHtml(runtimeText("companyViewLabel"))} ${escapeHtml(previewCompany.name || uiT("supportCompanyFallback"))}`
      : "";
    const needs2fa = state.currentUser?.role === "superadmin" && !Number(state.currentUser?.twofa_enabled);
    const twofaBanner = needs2fa
      ? `<p class="helper-text helper-text-warning" style="margin-top:8px;">${escapeHtml(uiT("bannerSuperadmin2fa"))}</p>`
      : "";
    elements.sessionCard.innerHTML = `<strong>${escapeHtml(texts.sessionLoggedIn)}:</strong> ${escapeHtml(user)} | <strong>${escapeHtml(texts.sessionRole)}:</strong> ${escapeHtml(role)}${supportModeMarkup}${previewMarkup}${twofaBanner}`;
  }

  if (!loggedIn) {
    stopInvoiceAutoRefresh();
    stopInvoiceApprovalAutoRefresh();
    return;
  }

  enforceRoleViewAccess();
  applyActiveCompanyBrandingPreset();

  renderStats();
  renderOperationsSnapshot();
  renderDashboardExpiringDocs();
  renderComplianceKpi();
  renderWorkerStatsPanel();
  renderReportingPanels();
  renderGateOpsMetrics();
  renderCustomerReviews();
  renderWorkerList();
  renderPhotoOverrideApprovalPanel();
  renderCompanyList();
  renderCompliancePanel();
  renderAuditLogPanel();
  populateWorkerSelectOptions();
  populateCompanySelectOptions();
  renderSystemIdentity();
  renderAdminSettingsForm();
  renderDashboardPorterLivePanel();
  renderRecentAccess();
  renderAccessLog();
  renderAccessSummary();
  renderAccessHourly();
  renderAccessWarnings();
  renderDayCloseBanner();
  renderTurnstileQuickPanel();
  renderPorterLivePanel();
  if (typeof window._refreshManualEntryListIfOpen === "function") window._refreshManualEntryListIfOpen();
  if (typeof window._syncManualEntryBtnVisibility === "function") window._syncManualEntryBtnVisibility();
  renderBadge();
  loadDevices();
  showLoginGreeting();
  renderTwofaPanel();
  renderInvoiceHistory();
  renderInvoiceManagementList();
  updateDocumentEmailInfoBar();
  renderDocumentInboxList();
  if (getCurrentViewName() === "invoices") {
    startInvoiceAutoRefresh();
  }
  ensureInvoiceDefaults();
  refreshInvoicePreview({ silent: true });
  applySupportReadOnlyUiState();
  renderEnterpriseNavMenu();
  applyDeepLinkViewFromUrl();
  if (loggedIn) {
    broadcastSessionToEmbeds();
    if (getCurrentViewName() === "dashboard") {
      startPlatformHealthPoll();
      startOpsLiveFeed();
    } else if (canViewPlatformHealth()) {
      void refreshPlatformHealth();
    }
  } else {
    stopPlatformHealthPoll();
    stopOpsLiveFeed();
  }
}

