function loadTtsVoiceList() {
  const panel = document.getElementById("ttsVoiceListPanel");
  if (!panel) return;

  if (!window.speechSynthesis) {
    panel.innerHTML = `
      <p style="color:#dc2626;font-size:0.88rem">â ïļ ${runtimeText("ttsUnsupportedTitle")}</p>
      <p style="color:#555;font-size:0.83rem;margin-top:6px">${runtimeText("ttsUnsupportedBrowserHint")}</p>`;
    return;
  }

  function renderVoices() {
    const voices = window.speechSynthesis.getVoices();
    if (!voices.length) {
      panel.innerHTML = `
        <div style="background:#fff8e1;border:1px solid #f59e0b;border-radius:6px;padding:12px;font-size:0.85rem">
          <p style="margin:0 0 8px;font-weight:600;color:#92400e">â ïļ ${runtimeText("ttsNoVoicesTitle")}</p>
          <p style="margin:0 0 6px;color:#555">${runtimeText("ttsNoVoicesCauses")}</p>
          <ul style="margin:0 0 10px;padding-left:18px;color:#555;line-height:1.7">
            <li>${runtimeText("ttsNoVoicesWindows")}</li>
            <li>${runtimeText("ttsNoVoicesChrome")}</li>
            <li>${runtimeText("ttsNoVoicesFirefox")}</li>
            <li>${runtimeText("ttsNoVoicesServer")}</li>
          </ul>
          <p style="margin:0;color:#555">${runtimeText("ttsNoVoicesJingleHint")}</p>
          <button type="button" class="ghost-button" style="margin-top:10px" onclick="loadTtsVoiceList()">ð ${runtimeText("ttsRetryBtn")}</button>
        </div>`;
      return;
    }

    const byLang = {};
    for (const v of voices) {
      const lang = v.lang || "unbekannt";
      if (!byLang[lang]) byLang[lang] = [];
      byLang[lang].push(v);
    }

    const langKeys = Object.keys(byLang).sort();
    const highlighted = ["de", "ar", "tr", "en", "fr", "es", "it", "pl"];

    let html = `<p style="font-size:0.82rem;color:#555;margin:0 0 10px">${runtimeTextTemplate("ttsVoicesAvailable", { count: voices.length })}</p>`;

    // Warnung wenn wichtige Sprachen fehlen
    const missingLangs = [];
    const availPrefixes = new Set(Object.keys(byLang).map((l) => l.split("-")[0].toLowerCase()));
    const needed = {
      ar: runtimeText("languageNameArabic"),
      tr: runtimeText("languageNameTurkish"),
      de: runtimeText("languageNameGerman"),
      en: runtimeText("languageNameEnglish"),
      fr: runtimeText("languageNameFrench"),
      es: runtimeText("languageNameSpanish"),
      it: runtimeText("languageNameItalian"),
      pl: runtimeText("languageNamePolish")
    };
    for (const [code, label] of Object.entries(needed)) {
      if (!availPrefixes.has(code)) missingLangs.push({ code, label });
    }
    if (missingLangs.length) {
      html += `<div style="background:#fff8e1;border:1px solid #f59e0b;border-radius:6px;padding:10px 12px;margin-bottom:10px;font-size:0.83rem">`;
      html += `<p style="margin:0 0 4px;font-weight:600;color:#92400e">â ïļ ${runtimeTextTemplate("ttsMissingLanguages", { languages: missingLangs.map((l) => l.label).join(", ") })}</p>`;
      html += `<p style="margin:0 0 6px;color:#555">${runtimeText("ttsInstallWindows")}</p>`;
      html += `<ol style="margin:0 0 6px;padding-left:18px;color:#555;line-height:1.75">`;
      html += `<li>${runtimeText("ttsInstallStep1")}</li>`;
      html += `<li>${runtimeText("ttsInstallStep2")}</li>`;
      html += `<li>${runtimeText("ttsInstallStep3")}</li>`;
      html += `<li>${runtimeText("ttsInstallStep4")}</li>`;
      html += `<li>${runtimeText("ttsInstallStep5")}</li>`;
      html += `</ol>`;
      html += `<p style="margin:0;color:#555">${runtimeText("ttsFallbackEnglish")}</p>`;
      html += `</div>`;
    }
    html += `<div style="max-height:400px;overflow-y:auto;font-size:0.83rem">`;
    for (const lang of langKeys) {
      const prefix = lang.split("-")[0].toLowerCase();
      const isHighlighted = highlighted.includes(prefix);
      const color = isHighlighted ? "#0f4c5c" : "#555";
      const weight = isHighlighted ? "600" : "400";
      const voiceCountLabel = byLang[lang].length === 1
        ? runtimeTextTemplate("ttsVoiceCountOne", { count: byLang[lang].length })
        : runtimeTextTemplate("ttsVoiceCountMany", { count: byLang[lang].length });
      html += `<div style="margin-bottom:6px">`;
      html += `<span style="font-weight:${weight};color:${color}">${escapeHtml(lang)}</span>`;
      html += `<span style="color:#999;margin-left:6px">(${escapeHtml(voiceCountLabel)})</span>`;
      html += `<div style="margin-left:12px;display:flex;flex-wrap:wrap;gap:4px;margin-top:3px">`;
      for (const v of byLang[lang]) {
        const label = v.name + (v.localService ? " ðĨïļ" : " âïļ");
        const voiceIdx = voices.indexOf(v);
        html += `<button type="button" class="ghost-button" style="font-size:0.78rem;padding:2px 7px"
          onclick="testTtsVoice(${voiceIdx})">${escapeHtml(label)}</button>`;
      }
      html += `</div></div>`;
    }
    html += `</div>`;
    html += `<p style="font-size:0.78rem;color:#888;margin-top:8px">${runtimeText("ttsLegend")}</p>`;
    panel.innerHTML = html;
  }

  panel.innerHTML = `<p style="color:#888;font-size:0.88rem">${runtimeText("ttsLoadingVoices")}</p>`;
  const voices = window.speechSynthesis.getVoices();
  if (voices.length > 0) {
    renderVoices();
  } else {
    window.speechSynthesis.addEventListener("voiceschanged", function once() {
      window.speechSynthesis.removeEventListener("voiceschanged", once);
      renderVoices();
    });
    setTimeout(renderVoices, 1200);
  }
}

function testTtsVoice(voiceIndex) {
  if (!window.speechSynthesis) return;
  const voices = window.speechSynthesis.getVoices();
  const voice = voices[voiceIndex];
  if (!voice) return;
  window.speechSynthesis.cancel();
  const lang = getStoredUiLang ? getStoredUiLang() : "de";
  const greetingMeta = getGreetingMeta(lang);
  const h = new Date().getHours();
  const text = h < 12 ? greetingMeta.morning : h < 18 ? greetingMeta.day : greetingMeta.evening;
  const utter = new SpeechSynthesisUtterance(text + "!");
  utter.voice  = voice;
  utter.lang   = voice.lang;
  utter.volume = 0.8;
  utter.rate   = 0.92;
  utter.pitch  = 1.15;
  window.speechSynthesis.speak(utter);
}

function playGreetingJingle() {
  // Freundlicher 3-Ton Jingle Ãžber Web Audio API â kein TTS nÃķtig
  try {
    const ctx = new (window.AudioContext || window.webkitAudioContext)();
    const notes = [523.25, 659.25, 783.99]; // C5, E5, G5 (Dur-Dreiklang)
    let startTime = ctx.currentTime + 0.05;
    for (const freq of notes) {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.type = "sine";
      osc.frequency.setValueAtTime(freq, startTime);
      gain.gain.setValueAtTime(0, startTime);
      gain.gain.linearRampToValueAtTime(0.18, startTime + 0.04);
      gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.45);
      osc.start(startTime);
      osc.stop(startTime + 0.5);
      startTime += 0.22;
    }
    // Kontext nach Ende schlieÃen
    setTimeout(() => { try { ctx.close(); } catch {} }, 2000);
  } catch {
    // AudioContext nicht verfÃžgbar â ignorieren
  }
}

function showLoginGreeting() {
  const user = state.currentUser;
  const el = document.getElementById("loginGreetingToast");
  if (!el || !user) return;

  // Nur einmal pro Tag anzeigen
  const today = new Date().toISOString().slice(0, 10); // "2026-04-21"
  const lastShown = localStorage.getItem(GREETING_SHOWN_KEY);
  if (lastShown === today) return;
  localStorage.setItem(GREETING_SHOWN_KEY, today);

  const lang = getStoredUiLang();
  const greetingMeta = getGreetingMeta(lang);
  const h = new Date().getHours();
  let salutation, icon, sub;
  if      (h >= 5  && h < 12) { salutation = greetingMeta.morning; icon = "âïļ";  sub = greetingMeta.subMorning; }
  else if (h >= 12 && h < 14) { salutation = greetingMeta.noon;    icon = "ðĪïļ"; sub = greetingMeta.subNoon; }
  else if (h >= 14 && h < 18) { salutation = greetingMeta.day;     icon = "ðĪïļ"; sub = greetingMeta.subDay; }
  else if (h >= 18 && h < 22) { salutation = greetingMeta.evening; icon = "ð";  sub = greetingMeta.subEvening; }
  else                         { salutation = greetingMeta.night;   icon = "ð";  sub = greetingMeta.subNight; }

  const firstName = (user.name || user.username || "").split(" ")[0];
  const fullSalutation = firstName ? `${salutation}, ${firstName}!` : `${salutation}!`;

  // Laufleiste Dauer setzen
  el.style.setProperty("--greet-duration", `${GREET_DISPLAY_MS / 1000}s`);

  const iconEl = document.getElementById("greetIcon");
  const salEl  = document.getElementById("greetSalutation");
  const subEl  = document.getElementById("greetSub");
  if (iconEl)  iconEl.textContent  = icon;
  if (salEl)   salEl.textContent   = fullSalutation;
  if (subEl)   subEl.textContent   = sub;

  el.classList.remove("hidden", "fade-out");

  // Text-to-Speech (Web Speech API) â spricht in der jeweiligen UI-Sprache
  try {
    if (window.speechSynthesis) {
      window.speechSynthesis.cancel();
      const ttsText = `${salutation}${firstName ? ", " + firstName : ""}!`;
      const ttsLang = greetingMeta.ttsLang;

      function speakWithVoice() {
        const utter = new SpeechSynthesisUtterance(ttsText);
        utter.lang   = ttsLang;
        utter.volume = 0.7;
        utter.rate   = 0.92;
        utter.pitch  = 1.15;
        const voices = window.speechSynthesis.getVoices();
        const prefix = ttsLang.split("-")[0].toLowerCase();

        const femaleKeywords = /female|frau|woman|fÃĐminin|feminine|zira|sabina|anna|lekha|helena|susan|karen|victoria|moira|samantha|ava|alice|amelie|cÃĐline|celine|hazel|heera|nora|laura|lucia|mia|paulina|kendra|joana|microsoft.*zira|google.*female/i;
        function isFemale(v) { return femaleKeywords.test(v.name); }

        // PrÃžfen ob fÃžr die gewÃžnschte Sprache Ãžberhaupt eine Stimme existiert
        const langAvailable = voices.some((v) => v.lang.toLowerCase().startsWith(prefix));

        let preferred;
        if (langAvailable) {
          // Normale Auswahl: weiblich > lokal > beliebig in der Zielsprache
          preferred =
            voices.find((v) => isFemale(v) && v.lang.toLowerCase() === ttsLang.toLowerCase() && v.localService) ||
            voices.find((v) => isFemale(v) && v.lang.toLowerCase().startsWith(prefix) && v.localService) ||
            voices.find((v) => isFemale(v) && v.lang.toLowerCase() === ttsLang.toLowerCase()) ||
            voices.find((v) => isFemale(v) && v.lang.toLowerCase().startsWith(prefix)) ||
            voices.find((v) => v.lang.toLowerCase() === ttsLang.toLowerCase() && v.localService) ||
            voices.find((v) => v.lang.toLowerCase().startsWith(prefix) && v.localService) ||
            voices.find((v) => v.lang.toLowerCase().startsWith(prefix));
        } else {
          // Zielsprache nicht verfÃžgbar â Fallback: weibliche Englisch-Stimme
          utter.lang = "en-GB";
          preferred =
            voices.find((v) => isFemale(v) && v.lang.toLowerCase().startsWith("en") && v.localService) ||
            voices.find((v) => isFemale(v) && v.lang.toLowerCase().startsWith("en")) ||
            voices.find((v) => v.lang.toLowerCase().startsWith("en") && v.localService) ||
            voices.find((v) => v.lang.toLowerCase().startsWith("en")) ||
            voices.find((v) => isFemale(v) && v.localService) ||
            voices.find((v) => isFemale(v));
        }
        if (preferred) utter.voice = preferred;
        window.speechSynthesis.speak(utter);
      }

      const voices = window.speechSynthesis.getVoices();
      if (voices.length > 0) {
        speakWithVoice();
      } else {
        window.speechSynthesis.addEventListener("voiceschanged", function onVoicesReady() {
          window.speechSynthesis.removeEventListener("voiceschanged", onVoicesReady);
          speakWithVoice();
        });
        // Fallback: nach 1s prÃžfen ob Stimmen jetzt da sind, sonst Jingle
        setTimeout(() => {
          if (!window.speechSynthesis.speaking) {
            if (window.speechSynthesis.getVoices().length > 0) {
              speakWithVoice();
            } else {
              // Keine Stimmen verfÃžgbar â kurzen Jingle Ãžber AudioContext abspielen
              playGreetingJingle();
            }
          }
        }, 1000);
      }
    }
  } catch {
    // Kein TTS verfÃžgbar â Jingle als Fallback
    try { playGreetingJingle(); } catch { /* ignore */ }
  }

  // Nach GREET_DISPLAY_MS ausblenden
  setTimeout(() => {
    el.classList.add("fade-out");
    setTimeout(() => el.classList.add("hidden"), 600);
  }, GREET_DISPLAY_MS);
}

// ââ Camera Management ââââââââââââââââââââââââââââââââââââââââââââââââââââââââ
let _cameraLiveTimer = null;
let _selectedCameraId = null;
state.siteCameras = state.siteCameras || [];

function _cameraEventsUrl() {
  let url = `${API_BASE}/api/integrations/cameras/events?limit=25`;
  const role = String(getCurrentUser()?.role || "");
  if (role === "superadmin" && superadminUiPreviewCompanyId) {
    url += `&company_id=${encodeURIComponent(superadminUiPreviewCompanyId)}`;
  }
  return url;
}

function _camerasApiUrl(suffix = "") {
  let url = `${API_BASE}/api/integrations/cameras${suffix}`;
  const role = String(getCurrentUser()?.role || "");
  if (role === "superadmin" && superadminUiPreviewCompanyId) {
    const sep = url.includes("?") ? "&" : "?";
    url += `${sep}company_id=${encodeURIComponent(superadminUiPreviewCompanyId)}`;
  }
  return url;
}

async function loadSiteCameras() {
  const role = String(getCurrentUser()?.role || "");
  if (!["superadmin", "company-admin"].includes(role)) return;
  if (role === "superadmin" && !superadminUiPreviewCompanyId) {
    state.siteCameras = [];
    renderSiteCameras();
    return;
  }
  try {
    const data = await apiRequest(_camerasApiUrl());
    state.siteCameras = Array.isArray(data?.cameras) ? data.cameras : [];
    renderSiteCameras(data?.summary);
  } catch (e) {
    console.warn("loadSiteCameras failed", e);
  }
}

function renderSiteCameras(summary) {
  const list = document.querySelector("#cameraList");
  const bar = document.querySelector("#cameraSummaryBar");
  const cameras = state.siteCameras || [];
  if (bar) {
    const total = summary?.total ?? cameras.length;
    const online = summary?.online ?? cameras.filter((c) => c.online).length;
    if (total > 0) {
      bar.classList.remove("hidden");
      bar.innerHTML = `<p style="margin:0;">${escapeHtml(uiT("cameraSummary").replace("{online}", online).replace("{total}", total))}</p>`;
    } else {
      bar.classList.add("hidden");
      bar.innerHTML = "";
    }
  }
  if (!list) return;
  if (!cameras.length) {
    list.innerHTML = `<p class="helper-text">${escapeHtml(uiT("camerasLiveEmpty"))}</p>`;
    return;
  }
  list.innerHTML = cameras
    .map((cam) => {
      const dotClass = cam.online ? "device-dot online" : cam.lastSeenAt ? "device-dot offline" : "device-dot";
      const statusLabel = cam.online
        ? uiT("cameraOnline")
        : cam.lastSeenAt
          ? uiT("cameraOffline")
          : uiT("cameraUnknown");
      const selected = _selectedCameraId === cam.id ? " camera-row-selected" : "";
      return `<div class="device-status-item${selected}" data-camera-id="${escapeHtml(cam.id)}">
        <span class="${dotClass}"></span>
        <span class="device-name">${escapeHtml(cam.name || cam.id)}</span>
        <span class="device-meta">${escapeHtml(cam.location || "")}</span>
        <span class="device-badge">${escapeHtml(statusLabel)}</span>
        <button type="button" class="ghost-button small-button camera-live-btn" data-camera-id="${escapeHtml(cam.id)}">${escapeHtml(uiT("cameraSelectLive"))}</button>
        <button type="button" class="ghost-button small-button camera-delete-btn" style="color:#dc2626;" data-camera-id="${escapeHtml(cam.id)}">â</button>
      </div>`;
    })
    .join("");
  list.querySelectorAll(".camera-live-btn").forEach((btn) => {
    btn.addEventListener("click", () => {
      _selectedCameraId = btn.getAttribute("data-camera-id");
      renderSiteCameras(summary);
      refreshCameraLiveView();
    });
  });
  list.querySelectorAll(".camera-delete-btn").forEach((btn) => {
    btn.addEventListener("click", async () => {
      const id = btn.getAttribute("data-camera-id");
      if (!(await showConfirmDialog(uiT("cameraDeleteConfirm")))) return;
      try {
        await apiRequest(_camerasApiUrl(`/${encodeURIComponent(id)}`), { method: "DELETE" });
        if (_selectedCameraId === id) _selectedCameraId = null;
        await loadSiteCameras();
        refreshCameraLiveView();
      } catch (err) {
        showToast(String(err?.message || err), "error");
      }
    });
  });
}

async function refreshCameraLiveView() {
  const img = document.querySelector("#cameraLiveImage");
  const placeholder = document.querySelector("#cameraLivePlaceholder");
  if (!img || !placeholder) return;
  if (!_selectedCameraId) {
    img.classList.add("hidden");
    placeholder.classList.remove("hidden");
    placeholder.textContent = uiT("camerasLiveEmpty");
    return;
  }
  const role = String(getCurrentUser()?.role || "");
  if (role === "superadmin" && !superadminUiPreviewCompanyId) return;
  try {
    let url = `${API_BASE}/api/integrations/cameras/${encodeURIComponent(_selectedCameraId)}/snapshot?format=jpeg&_=${Date.now()}`;
    if (role === "superadmin" && superadminUiPreviewCompanyId) {
      url += `&company_id=${encodeURIComponent(superadminUiPreviewCompanyId)}`;
    }
    const resp = await fetch(url, {
      headers: token ? { Authorization: `Bearer ${token}` } : {},
      credentials: "include",
    });
    if (!resp.ok) throw new Error("no_snapshot");
    const blob = await resp.blob();
    img.src = URL.createObjectURL(blob);
    img.classList.remove("hidden");
    placeholder.classList.add("hidden");
  } catch {
    img.classList.add("hidden");
    placeholder.classList.remove("hidden");
    placeholder.textContent = uiT("camerasLiveEmpty");
  }
}

function startCameraLivePolling() {
  stopCameraLivePolling();
  _cameraLiveTimer = setInterval(() => {
    if (_selectedCameraId) void refreshCameraLiveView();
  }, 10000);
}

function stopCameraLivePolling() {
  if (_cameraLiveTimer) {
    clearInterval(_cameraLiveTimer);
    _cameraLiveTimer = null;
  }
}

async function loadCameraEvents() {
  const list = document.querySelector("#cameraEventsList");
  if (!list) return;
  const role = String(getCurrentUser()?.role || "");
  if (!["superadmin", "company-admin"].includes(role)) {
    list.innerHTML = "";
    return;
  }
  if (role === "superadmin" && !superadminUiPreviewCompanyId) {
    list.innerHTML = `<p class="helper-text">${escapeHtml(uiT("camerasEventsEmpty"))}</p>`;
    return;
  }
  try {
    const data = await apiRequest(_cameraEventsUrl());
    const events = Array.isArray(data?.events) ? data.events : [];
    if (!events.length) {
      list.innerHTML = `<p class="helper-text">${escapeHtml(uiT("camerasEventsEmpty"))}</p>`;
      return;
    }
    list.innerHTML = events
      .map((ev) => {
        let payload = {};
        try {
          payload = typeof ev.payload_json === "string" ? JSON.parse(ev.payload_json) : (ev.payload_json || {});
        } catch {
          payload = {};
        }
        const analysis = payload.analysis || {};
        const alerts = Array.isArray(analysis.alerts) ? analysis.alerts : [];
        const face = payload.face_match;
        const faceTag = face === true
          ? `<span class="helper-text helper-text-ok">${escapeHtml(uiT("cameraEventFaceOk"))}</span>`
          : face === false
            ? `<span class="helper-text helper-text-warning">${escapeHtml(uiT("cameraEventFaceNo"))}</span>`
            : "";
        const alertTags = alerts
          .slice(0, 2)
          .map((a) => `<span class="helper-text helper-text-warning">${escapeHtml(a.message || a.type || "")}</span>`)
          .join(" ");
        const workerLine = ev.worker_id
          ? ` Â· ${escapeHtml(uiT("cameraEventWorker"))}: ${escapeHtml(ev.worker_id)}`
          : "";
        const zoneTag = Number(ev.zone_violation) === 1
          ? `<span class="helper-text helper-text-warning">${escapeHtml(uiT("cameraEventZoneAlert"))}</span>`
          : "";
        const ppeTag = ev.ppe_compliant === 0
          ? `<span class="helper-text helper-text-warning">${escapeHtml(uiT("cameraEventPpeMissing"))}</span>`
          : "";
        return `
        <article class="card-item" style="margin-bottom:6px;">
          <strong>${escapeHtml(ev.event_type || "event")}</strong>
          <span class="meta-text"> Â· ${escapeHtml(ev.camera_id || "-")}</span>
          ${faceTag ? ` ${faceTag}` : ""}
          ${ppeTag ? ` ${ppeTag}` : ""}
          ${zoneTag ? ` ${zoneTag}` : ""}
          ${alertTags ? ` ${alertTags}` : ""}
          <p class="helper-text">${escapeHtml(ev.created_at || "")}${workerLine}</p>
        </article>`;
      })
      .join("");
  } catch {
    list.innerHTML = "";
  }
}

async function refreshCamerasPanel() {
  await Promise.all([loadSiteCameras(), loadCameraEvents()]);
}

