async function downloadPayrollDatevCsv() {
  const role = String(getCurrentUser()?.role || "").toLowerCase();
  let companyId = String(getCurrentUser()?.company_id || getCurrentUser()?.companyId || "").trim();
  if (role === "superadmin") {
    companyId = String(superadminUiPreviewCompanyId || "").trim();
    if (!companyId && Array.isArray(state.companies) && state.companies.length) {
      companyId = String(state.companies[0].id || "").trim();
    }
    if (!companyId) {
      showToast("Bitte zuerst eine Firma in der Vorschau wÃĪhlen.");
      return;
    }
  }
  const period = window.prompt("Abrechnungszeitraum (YYYY-MM, leer = gesamt):", new Date().toISOString().slice(0, 7));
  if (period === null) return;
  const periodParam = String(period || "").trim();
  const url = `${API_BASE}/api/documents/payroll/datev-export?companyId=${encodeURIComponent(companyId)}&period=${encodeURIComponent(periodParam)}`;
  const sessionToken = token || loadStoredSessionToken();
  const response = await fetch(url, {
    credentials: "include",
    headers: sessionToken ? { Authorization: `Bearer ${sessionToken}` } : {},
  });
  if (!response.ok) {
    const err = await response.json().catch(() => ({}));
    throw new Error(err.message || err.error || `HTTP ${response.status}`);
  }
  const blob = await response.blob();
  const link = document.createElement("a");
  link.href = URL.createObjectURL(blob);
  link.download = `datev-lohn-${companyId}-${periodParam || "gesamt"}.csv`;
  link.click();
  URL.revokeObjectURL(link.href);
}

function suggestCompanyDocumentEmail(companyName) {
  const baseAddress = String(
    state.settings?.imapUsername ||
    state.settings?.smtpUsername ||
    state.settings?.smtpSenderEmail ||
    ""
  ).trim().toLowerCase();
  if (!companyName || !baseAddress.includes("@")) {
    return "";
  }
  const slug = String(companyName)
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 48) || "firma";
  const [localPart, domain] = baseAddress.split("@", 2);
  const normalizedDomain = String(domain || "").trim().toLowerCase();
  const aliasBase = (localPart.split("+", 1)[0] || "dokumente").trim() || "dokumente";
  const plusUnreliableDomains = new Set(["gmx.de", "gmx.net", "gmx.com", "web.de"]);
  if (plusUnreliableDomains.has(normalizedDomain)) {
    return "";
  }
  return `${aliasBase}+${slug}@${domain}`;
}

function hasUnsupportedImapPlusAliasDomain(rawEmail) {
  const normalized = String(rawEmail || "").trim().toLowerCase();
  if (!normalized.includes("@")) {
    return false;
  }
  const domain = normalized.split("@").pop() || "";
  return new Set(["gmx.de", "gmx.net", "gmx.com", "web.de"]).has(domain);
}

function renderImapPlusAliasWarning() {
  const warningEl = document.querySelector("#imapPlusAliasHint");
  if (!warningEl) {
    return;
  }
  const imapUsername = document.querySelector("#imapUsername")?.value || state.settings?.imapUsername || "";
  const shouldShow = hasUnsupportedImapPlusAliasDomain(imapUsername);
  warningEl.textContent = shouldShow ? uiT("imapPlusAliasWarning") : "";
  warningEl.style.display = shouldShow ? "block" : "none";
}

