// ââ Mitarbeiter-Dokumente laden + rendern ââââââââââââââââââââââââââââââââââ

async function loadWorkerDocuments(workerId) {
  try {
    return await apiRequest(`${API_BASE}/api/workers/${encodeURIComponent(workerId)}/documents`);
  } catch {
    return [];
  }
}

function renderWorkerDocuments(docs, workerId, container) {
  const role = getCurrentUser()?.role || "";
  const canDelete = ["superadmin", "company-admin"].includes(role);
  const canUpload = ["superadmin", "company-admin", "turnstile"].includes(role);
  const ALL_DOC_TYPES = [
    "mindestlohnnachweis", "personalausweis", "sozialversicherungsnachweis",
    "arbeitserlaubnis", "gesundheitszeugnis", "lohnabrechnung", "gehaltsabrechnung", "sonstiges",
  ];
  const DOC_TYPES_REQUIRE_EXPIRY = new Set(["personalausweis", "arbeitserlaubnis", "gesundheitszeugnis"]);

  const docTypeLabel = (t) => {
    const key = `docType${t.charAt(0).toUpperCase()}${t.slice(1)}`;
    return uiT(key) || t;
  };

  const docsHtml = docs.length === 0
    ? `<p class="muted" style="font-size:0.88em;">${escapeHtml(uiT("workerDocsEmpty"))}</p>`
    : docs.map((doc) => {
      const typeLabel = docTypeLabel(doc.doc_type || "");
      const date = (doc.created_at || "").slice(0, 10);
      const expiry = doc.expiry_date ? ` Â· ${escapeHtml(uiT("docExpiryLabel"))}: ${escapeHtml(doc.expiry_date)}` : "";
      const notes = doc.notes ? ` Â· ${escapeHtml(doc.notes)}` : "";
      const deleteBtn = canDelete
        ? `<button type="button" class="ghost-button small-button" data-delete-doc="${escapeHtml(doc.id)}" style="color:#e53e3e;font-size:0.8em;">${escapeHtml(uiT("btnDeleteDoc"))}</button>`
        : "";
      return `
        <div style="display:flex;justify-content:space-between;align-items:center;gap:8px;padding:5px 0;border-bottom:1px solid #f0f0f0;font-size:0.85em;">
          <div style="min-width:0;flex:1;">
            <strong>${escapeHtml(typeLabel)}</strong>
            <span class="muted"> Â· ${escapeHtml(doc.filename)}${expiry}${notes} Â· ${escapeHtml(date)}</span>
          </div>
          <div style="display:flex;gap:4px;flex-shrink:0;">
            <button type="button" class="ghost-button small-button" data-download-doc="${escapeHtml(doc.id)}" data-doc-filename="${escapeHtml(doc.filename)}" style="font-size:0.8em;">${escapeHtml(uiT("btnDownloadDoc"))}</button>
            ${deleteBtn}
          </div>
        </div>`;
    }).join("");

  const uploadHtml = canUpload ? `
    <details style="margin-top:8px;">
      <summary style="cursor:pointer;font-size:0.85em;color:#4a90d9;">${escapeHtml(uiT("btnUploadWorkerDoc"))}</summary>
      <form class="worker-doc-upload-form" style="display:grid;gap:6px;margin-top:8px;">
        <select name="docType" required style="padding:5px;border:1px solid #cbd5e0;border-radius:4px;font-size:0.85em;">
          <option value="">${escapeHtml(runtimeText("docTypePlaceholder"))}</option>
          ${ALL_DOC_TYPES.map((t) => `<option value="${t}">${escapeHtml(docTypeLabel(t))}</option>`).join("")}
        </select>
        <div class="doc-expiry-row" style="display:none;">
          <label style="font-size:0.85em;">${escapeHtml(uiT("docExpiryLabel"))}
            <input type="date" name="expiryDate" style="margin-left:6px;padding:4px;border:1px solid #cbd5e0;border-radius:4px;" />
          </label>
        </div>
        <input type="file" name="file" accept=".pdf,.jpg,.jpeg,.png,.gif,.webp,.doc,.docx" required style="font-size:0.85em;" />
        <textarea name="notes" placeholder="${escapeAttr("Notizen (optional)")}" rows="2" style="padding:5px;border:1px solid #cbd5e0;border-radius:4px;font-size:0.85em;resize:vertical;"></textarea>
        <button type="submit" class="primary-button small-button" style="font-size:0.85em;">${escapeHtml(uiT("btnConfirmUpload"))}</button>
      </form>
    </details>` : "";

  container.innerHTML = docsHtml + uploadHtml;

  // Download handlers
  container.querySelectorAll("[data-download-doc]").forEach((btn) => {
    btn.addEventListener("click", async () => {
      btn.disabled = true;
      try {
        const docId = btn.dataset.downloadDoc;
        const filename = btn.dataset.docFilename || "dokument";
        const response = await fetch(
          `${API_BASE}/api/workers/${encodeURIComponent(workerId)}/documents/${encodeURIComponent(docId)}/download`,
          { headers: { Authorization: `Bearer ${token}` }, credentials: "include" }
        );
        if (!response.ok) {
          let backendError = "";
          try {
            const payload = await response.json();
            backendError = String(payload?.error || "").trim();
          } catch {
            backendError = "";
          }
          if (response.status === 404) {
            throw new Error(runtimeText("docNotFoundError"));
          }
          throw new Error(backendError || `HTTP ${response.status}`);
        }
        const blob = await response.blob();
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = filename;
        document.body.appendChild(a);
        a.click();
        a.remove();
        URL.revokeObjectURL(url);
      } catch (err) {
        showToast(`Download fehlgeschlagen: ${err.message}`, "error", 3600);
        if (String(err?.message || "").toLowerCase().includes("dokument nicht gefunden")) {
          try {
            const updatedDocs = await loadWorkerDocuments(workerId);
            renderWorkerDocuments(updatedDocs, workerId, container);
          } catch {
            // ignore refresh errors and keep current UI state
          }
        }
      } finally {
        btn.disabled = false;
      }
    });
  });

  // Delete handlers
  container.querySelectorAll("[data-delete-doc]").forEach((btn) => {
    btn.addEventListener("click", async () => {
      if (!(await showConfirmDialog(uiT("confirmDeleteDoc")))) return;
      btn.disabled = true;
      try {
        const docId = btn.dataset.deleteDoc;
        await apiRequest(
          `${API_BASE}/api/workers/${encodeURIComponent(workerId)}/documents/${encodeURIComponent(docId)}`,
          { method: "DELETE" }
        );
        const updatedDocs = await loadWorkerDocuments(workerId);
        renderWorkerDocuments(updatedDocs, workerId, container);
      } catch (err) {
        showToast(runtimeText("docDeleteFailed").replace("{error}", err.message), "error", 3600);
        btn.disabled = false;
      }
    });
  });

  // Upload form handler
  const form = container.querySelector(".worker-doc-upload-form");
  if (form) {
    const docTypeSelect = form.querySelector("select[name=docType]");
    const expiryRow = form.querySelector(".doc-expiry-row");
    const expiryInput = form.querySelector("input[name=expiryDate]");

    docTypeSelect.addEventListener("change", () => {
      const needsExpiry = DOC_TYPES_REQUIRE_EXPIRY.has(docTypeSelect.value);
      expiryRow.style.display = needsExpiry ? "block" : "none";
      expiryInput.required = needsExpiry;
    });

    form.addEventListener("submit", async (e) => {
      e.preventDefault();
      const submitBtn = form.querySelector("button[type=submit]");
      if (submitBtn) submitBtn.disabled = true;
      try {
        const formData = new FormData();
        formData.append("docType", docTypeSelect.value);
        formData.append("expiryDate", expiryInput.value || "");
        formData.append("notes", (form.querySelector("textarea[name=notes]").value || "").trim());
        const fileInput = form.querySelector("input[name=file]");
        if (fileInput.files[0]) formData.append("file", fileInput.files[0]);

        const response = await fetch(
          `${API_BASE}/api/workers/${encodeURIComponent(workerId)}/documents/upload`,
          { method: "POST", headers: { Authorization: `Bearer ${token}` }, credentials: "include", body: formData }
        );
        const result = await response.json().catch(() => ({}));
        if (!response.ok) throw new Error(result?.error || `HTTP ${response.status}`);

        showToast(uiT("docUploadSuccess"), "success");
        const updatedDocs = await loadWorkerDocuments(workerId);
        renderWorkerDocuments(updatedDocs, workerId, container);
      } catch (err) {
        showToast(`Upload fehlgeschlagen: ${err.message}`, "error", 3600);
        if (submitBtn) submitBtn.disabled = false;
      }
    });
  }
}

// Zeige Mitarbeiterdetails direkt im Dashboard-Bereich
function renderDashboardWorkerDetail(worker, options = {}) {
  // Overlay und Detail-Elemente holen
  const overlay = document.getElementById("dashboardDetailOverlay");
  const detail = document.getElementById("dashboardWorkerDetail");
  if (!overlay || !detail) return;
  const sourceView = options.sourceView || getCurrentViewName();
  const workerCompanyId = getWorkerCompanyId(worker);
  const company = state.companies.find((entry) => entry.id === workerCompanyId);
  const subcompanyLabel = getSubcompanyLabel(worker);
  const safePhoto = sanitizeImageSrc(worker.photoData, createAvatar(worker));
  const latestAccess = getLatestAccessForWorker(worker.id)
    || [...state.accessLogs]
      .filter((entry) => entry.workerId === worker.id)
      .sort((left, right) => right.timestamp.localeCompare(left.timestamp))[0]
    || null;
  const statusValueMap = {
    aktiv: uiT("optStatusActive"),
    gesperrt: uiT("optStatusLocked"),
    abgelaufen: uiT("optStatusExpired")
  };
  const statusLabel = statusValueMap[String(worker.status || "").trim().toLowerCase()] || worker.status;
  const latestDirectionLabel = latestAccess
    ? latestAccess.direction === "check-in"
      ? runtimeText("dashboardDirectionCheckin")
      : runtimeText("dashboardDirectionCheckout")
    : "";
  detail.innerHTML = `
    <button class="close-btn" title="${escapeHtml(uiT("detailCloseTitle"))}">&times;</button>
    <div class="worker-detail-card">
      <img src="${safePhoto}" alt="${escapeHtml(uiT("detailPhotoAlt"))}" />
      <h2>${escapeHtml(worker.firstName)} ${escapeHtml(worker.lastName)}</h2>
      <p><strong>${escapeHtml(uiT("labelFirm"))}:</strong> ${escapeHtml(company?.name || "-")}</p>
      ${subcompanyLabel ? `<p><strong>${escapeHtml(uiT("labelSubcompany"))}:</strong> ${escapeHtml(subcompanyLabel)}</p>` : ""}
      <p><strong>${escapeHtml(uiT("badgeLabelBadgeId"))}:</strong> ${escapeHtml(worker.badgeId)}</p>
      <p><strong>${escapeHtml(uiT("labelInsuranceNumber"))}:</strong> ${escapeHtml(worker.insuranceNumber)}</p>
      <p><strong>${escapeHtml(uiT("labelRoleField"))}:</strong> ${escapeHtml(worker.role)}</p>
      <p><strong>${escapeHtml(uiT("labelSite"))}:</strong> ${escapeHtml(worker.site || "-")}</p>
      <p><strong>${escapeHtml(uiT("labelValidUntil"))}:</strong> ${formatDate(worker.validUntil)}</p>
      <p><strong>${escapeHtml(uiT("labelWorkerStatus"))}:</strong> ${escapeHtml(statusLabel || "")}</p>
      <p><strong>${escapeHtml(uiT("labelBadgePin"))}:</strong> ${escapeHtml(worker.badgePinConfigured ? uiT("pinSet") : uiT("pinMissing"))}</p>
      <p><strong>${escapeHtml(uiT("cardLabel"))}:</strong> ${escapeHtml(worker.physicalCardId || uiT("cardUnassigned"))}</p>
      <p><strong>${escapeHtml(runtimeText("dashboardLastAccessHeading"))}:</strong> ${escapeHtml(latestDirectionLabel || runtimeText("dashboardLastAccessPlaceholder"))}</p>
      ${latestAccess ? `<p><strong>${escapeHtml(runtimeText("accessWarningGate"))}:</strong> ${escapeHtml(latestAccess.gate || runtimeText("unknownTurnstile"))}</p>` : ""}
      ${latestAccess ? `<p><strong>${escapeHtml(runtimeText("summaryLastBooking"))}:</strong> ${escapeHtml(formatTimestamp(latestAccess.timestamp))}</p>` : ""}
      <div class="button-row dashboard-worker-detail-actions">
        <button type="button" class="primary-button" data-worker-id="${escapeHtml(worker.id)}" data-direction="check-in" data-source-view="${escapeHtml(sourceView)}">${escapeHtml(uiT("detailCheckinBtn"))}</button>
        <button type="button" class="ghost-button" data-worker-id="${escapeHtml(worker.id)}" data-direction="check-out" data-source-view="${escapeHtml(sourceView)}">${escapeHtml(uiT("detailCheckoutBtn"))}</button>
      </div>
    </div>
  `;
  overlay.classList.remove("hidden");
  detail.querySelector(".close-btn").onclick = () => overlay.classList.add("hidden");
  overlay.onclick = (e) => { if (e.target === overlay) overlay.classList.add("hidden"); };
  detail.querySelectorAll("[data-worker-id][data-direction]").forEach((button) => {
    button.addEventListener("click", () => {
      const targetWorker = state.workers.find((item) => item.id === button.dataset.workerId);
      if (!targetWorker) {
        return;
      }
      triggerWorkerAccess(targetWorker, button.dataset.direction, {
        sourceView: button.dataset.sourceView || sourceView
      });
    });
  });
}

function renderAccessLog() {
  document.querySelector("#accessFrom").value = state.accessFilter.from;
  document.querySelector("#accessTo").value = state.accessFilter.to;
  document.querySelector("#accessFilterDirection").value = state.accessFilter.direction;
  document.querySelector("#accessFilterGate").value = state.accessFilter.gate;

  const entries = getUiVisibleAccessLogs().sort((left, right) => right.timestamp.localeCompare(left.timestamp));

  if (!entries.length) {
    elements.accessLogList.innerHTML = `<div class="empty-state">${runtimeText("accessFilterEmpty")}</div>`;
    return;
  }

  const loadMoreMarkup = state.accessLogsMeta?.hasMore
    ? `
      <div class="button-row" style="justify-content:center; margin-top:12px;">
        <button type="button" class="ghost-button small-button" data-access-load-more>${escapeHtml(runtimeText("accessLoadMoreButton") || "Mehr laden")}</button>
      </div>
    `
    : "";

  elements.accessLogList.innerHTML = entries.map(renderAccessItem).join("") + loadMoreMarkup;

  // Klick auf Mitarbeiter-Eintrag -> neutralen Detaildialog oeffnen
  elements.accessLogList.querySelectorAll("article[data-worker-id]").forEach((item) => {
    const wid = item.dataset.workerId;
    if (!wid) return;
    item.addEventListener("click", () => {
      const w = state.workers.find((x) => x.id === wid);
      if (w) renderDashboardWorkerDetail(w);
    });
  });

  const loadMoreButton = elements.accessLogList.querySelector("[data-access-load-more]");
  if (loadMoreButton) {
    loadMoreButton.addEventListener("click", async () => {
      loadMoreButton.disabled = true;
      try {
        const loaded = await loadMoreAccessLogs();
        if (loaded) {
          renderAccessLog();
          renderAccessSummary();
        } else {
          state.accessLogsMeta = { ...state.accessLogsMeta, hasMore: false };
          renderAccessLog();
        }
      } catch (error) {
        loadMoreButton.disabled = false;
        showToast(uiT("alertAccessBookingFailed").replace("{error}", error.message));
      }
    });
  }
}

function renderAccessSummary() {
  const entries = getUiVisibleAccessLogs();
  if (!entries.length) {
    elements.accessSummaryGrid.innerHTML = `<div class="empty-state">${runtimeText("dayReportEmpty")}</div>`;
    return;
  }

  const grouped = new Map();
  entries.forEach((entry) => {
    const gateKey = (entry.gate || runtimeText("unknownTurnstile")).trim() || runtimeText("unknownTurnstile");
    const current = grouped.get(gateKey) || {
      gate: gateKey,
      total: 0,
      checkIn: 0,
      checkOut: 0,
      latest: "",
      visitors: []
    };

    const worker = state.workers.find((item) => item.id === entry.workerId);
    const visitorName = worker ? `${worker.firstName} ${worker.lastName}` : `${runtimeText("accessSummaryUnknownWorker")} ${entry.workerId}`;
    const visitorMeta = worker && isVisitorWorker(worker)
      ? `${worker.visitorCompany || runtimeText("visitorCompanyFallback")} | ${worker.visitPurpose || runtimeText("visitPurposeFallback")}`
      : "";

    current.total += 1;
    if (entry.direction === "check-in") {
      current.checkIn += 1;
    }
    if (entry.direction === "check-out") {
      current.checkOut += 1;
    }
    if (!current.latest || entry.timestamp > current.latest) {
      current.latest = entry.timestamp;
    }
    const visitorLabel = visitorMeta ? `${visitorName} (${visitorMeta})` : visitorName;
    if (!current.visitors.includes(visitorLabel)) {
      current.visitors.push(visitorLabel);
    }

    grouped.set(gateKey, current);
  });

  const cards = Array.from(grouped.values()).sort((a, b) => a.gate.localeCompare(b.gate));
  elements.accessSummaryGrid.innerHTML = cards
    .map(
      (item) => `
        <article class="summary-card">
          <strong>${escapeHtml(item.gate)}</strong>
          <span>${runtimeText("summaryEntries")}: ${item.checkIn}</span>
          <span>${runtimeText("summaryExits")}: ${item.checkOut}</span>
          <span>${runtimeText("summaryTotal")}: ${item.total}</span>
          <span>${runtimeText("summaryLastBooking")}: ${formatTimestamp(item.latest)}</span>
          <div class="summary-visitor-block">
            <span class="summary-visitor-title">${runtimeText("summaryPeople")}:</span>
            <div class="summary-visitor-list">${item.visitors.map((name) => `<span class="summary-visitor-pill">${escapeHtml(name)}</span>`).join("")}</div>
          </div>
        </article>
      `
    )
    .join("");
}

