let smtpTestInFlight = false;
async function sendSmtpTestMail() {
  if (smtpTestInFlight) return;
  smtpTestInFlight = true;
  const btn = document.querySelector("#smtpTestBtn");
  const result = document.querySelector("#smtpTestResult");
  if (btn) btn.disabled = true;
  if (result) result.textContent = `âģ ${runtimeText("smtpSending")}`;
  try {
    const res = await apiRequest(API_BASE + "/api/settings/smtp-test", {
      method: "POST",
      body: getCurrentSmtpSettingsFromForm()
    });
    if (!res?.ok) {
      throw {
        code: res?.error || "smtp_send_failed",
        payload: res,
        message: res?.detail || runtimeText("smtpSendFailed")
      };
    }
    if (result) {
      result.style.color = "#16a34a";
      if (res?.delivery && res.delivery !== "smtp") {
        result.textContent = `â ${runtimeTextTemplate("smtpSentToFallback", { recipient: res.recipient })}`;
      } else {
        result.textContent = `â ${runtimeTextTemplate("smtpSentTo", { recipient: res.recipient })}`;
      }
    }
  } catch (err) {
    if (result) {
      result.style.color = "#dc2626";
      let message = formatSmtpTestError(err);
      const hasInlineDiag = Boolean(err?.payload?.diagnostics);
      if (!hasInlineDiag) {
        try {
          const diag = await runSmtpDiagnostics();
          const diagText = formatSmtpDiagnosticsPayload(diag);
          if (diagText) message += ` | ${diagText}`;
        } catch (diagErr) {
          const diagText = formatSmtpDiagnosticsPayload(diagErr?.payload);
          if (diagText) message += ` | ${diagText}`;
        }
      }
      const isConnectFailure = String(err?.payload?.diagnostics?.stage || "") === "connect";
      if (isConnectFailure) {
        const fallbackRecipient = document.querySelector("#smtpSenderEmail")?.value.trim() || "";
        const apiCheck = await runResendDirectTest(fallbackRecipient);
        if (apiCheck?.ok) {
          message += ` | ${runtimeText("smtpDirectApiTestOk")}`;
        } else if (apiCheck?.error) {
          const apiSource = apiCheck?.resendKeySource ? ` (${apiCheck.resendKeySource})` : "";
          message += ` | ${runtimeTextTemplate("smtpDirectApiTestResult", {
            error: apiCheck.error,
            source: apiSource
          })}`;
        }
      }
      result.textContent = `â ${runtimeTextTemplate("genericErrorPrefix", { message })}`;
    }
  } finally {
    if (btn) btn.disabled = false;
    smtpTestInFlight = false;
  }
}

function renderReadinessPill(label, ok) {
  const cls = ok ? "status-ok" : "status-test";
  const text = ok ? uiT("readinessStatusOk") : uiT("readinessStatusWarn");
  return `<span class="status-pill ${cls}" style="margin:2px 4px 2px 0;">${escapeHtml(label)}: ${escapeHtml(text)}</span>`;
}

function renderProductReadinessPanel(statusPayload) {
  const panel = document.getElementById("productReadinessPanel");
  if (!panel) return;
  if (!statusPayload) {
    panel.innerHTML = `<p class="muted">${escapeHtml(runtimeText("genericUnknownError"))}</p>`;
    return;
  }
  const wallet = statusPayload.wallet || {};
  const appleOk = Boolean(wallet?.runtime?.apple?.ok);
  const googleOk = Boolean(wallet?.runtime?.google?.ok);
  const installUrl = String(statusPayload.workerInstallUrl || "").trim();
  panel.innerHTML = `
    <div style="display:flex;flex-wrap:wrap;gap:4px;margin-bottom:10px;">
      ${renderReadinessPill(uiT("readinessAppleWallet"), appleOk)}
      ${renderReadinessPill(uiT("readinessGoogleWallet"), googleOk)}
      ${renderReadinessPill(uiT("readinessSmtp"), Boolean(statusPayload.smtpConfigured))}
      ${renderReadinessPill(uiT("readinessRedis"), Boolean(statusPayload.redisReady))}
      ${renderReadinessPill(uiT("readinessDbBackups"), Number(statusPayload.dbBackupCount || 0) > 0)}
    </div>
    <p class="helper-text" style="margin:0 0 6px;"><strong>${escapeHtml(uiT("readinessWorkerInstall"))}</strong></p>
    <p style="margin:0 0 8px;font-size:0.82rem;word-break:break-all;">${escapeHtml(installUrl || "-")}</p>
    ${installUrl ? `<button type="button" class="ghost-button small-button" id="copyWorkerInstallUrlBtn">${escapeHtml(uiT("readinessCopyInstall"))}</button>` : ""}
  `;
  const copyBtn = panel.querySelector("#copyWorkerInstallUrlBtn");
  if (copyBtn && installUrl) {
    copyBtn.onclick = async () => {
      try {
        await navigator.clipboard.writeText(installUrl);
        showToast(uiT("readinessInstallCopied"), "success");
      } catch (_err) {
        showToast(installUrl, "info", 5000);
      }
    };
  }
}

function renderSystemStatusPanel(statusPayload) {
  const panel = document.querySelector("#systemStatusPanel");
  if (!panel) return;

  if (!statusPayload) {
    panel.innerHTML = `<p>${escapeHtml(runtimeTextTemplate("systemStatusLoadFailed", { error: runtimeText("genericUnknownError") }))}</p>`;
    return;
  }

  const activeSessions = Number(statusPayload.activeSessions || 0);
  const activeWorkerSessions = Number(statusPayload.activeWorkerSessions || 0);
  const openEntries = Number(statusPayload.openEntries || 0);
  const loginLocks = Array.isArray(statusPayload.loginLocks) ? statusPayload.loginLocks.length : 0;
  const recentIssues = Array.isArray(statusPayload.recentIssues) ? statusPayload.recentIssues.length : 0;
  const serverTime = formatTimestamp(statusPayload.serverTime || new Date().toISOString());
  const warnings = Array.isArray(statusPayload.runtimeWarnings) ? statusPayload.runtimeWarnings : [];
  const warningLines = warnings.slice(0, 5).map((w) => `<li>${escapeHtml(w.message || w.code || "")}</li>`).join("");

  panel.innerHTML = `
    <p><strong>${escapeHtml(runtimeText("systemStatusServerTime"))}:</strong> ${escapeHtml(serverTime)}</p>
    <p><strong>${escapeHtml(runtimeText("systemStatusActiveAdminSessions"))}:</strong> ${activeSessions}</p>
    <p><strong>${escapeHtml(runtimeText("systemStatusActiveWorkerSessions"))}:</strong> ${activeWorkerSessions}</p>
    <p><strong>${escapeHtml(runtimeText("systemStatusOpenEntries"))}:</strong> ${openEntries}</p>
    <p><strong>${escapeHtml(runtimeText("systemStatusLoginLocks"))}:</strong> ${loginLocks}</p>
    <p><strong>${escapeHtml(runtimeText("systemStatusRecentIssues"))}:</strong> ${recentIssues}</p>
    ${warningLines ? `<ul class="helper-text" style="margin:8px 0 0;padding-left:18px;">${warningLines}</ul>` : ""}
  `;
  renderProductReadinessPanel(statusPayload);
}

async function refreshSystemStatus() {
  const panel = document.querySelector("#systemStatusPanel");
  if (panel) {
    panel.innerHTML = `<p>${escapeHtml(runtimeText("systemStatusLoading"))}</p>`;
  }

  try {
    const status = await apiRequest(`${API_BASE}/api/system/status`, { method: "GET" });
    renderSystemStatusPanel(status);
  } catch (error) {
    if (panel) {
      panel.innerHTML = `<p>${escapeHtml(runtimeTextTemplate("systemStatusLoadFailed", { error: error.message }))}</p>`;
    }
  }
}

async function handleSystemRepair() {
  if (!(await showConfirmDialog(uiT("confirmSystemRepair")))) {
    return;
  }

  try {
    await apiRequest(`${API_BASE}/api/system/repair`, { method: "POST", body: {} });
    await refreshSystemStatus();
    showToast(uiT("alertSystemRepairDone"), "success");
  } catch (error) {
    showToast(uiT("alertSystemRepairFailed").replace("{error}", error.message), "error", 3600);
  }
}

async function handleInvoiceLogoUpload(event) {
  const file = event.target.files?.[0];
  if (!file) {
    return;
  }

  if (!file.type.startsWith("image/")) {
    showToast(runtimeText("logoImageFileRequired"));
    return;
  }

  const reader = new FileReader();
  reader.onload = () => {
    const dataUrl = typeof reader.result === "string" ? reader.result : "";
    elements.invoiceLogoData.value = dataUrl;
    elements.invoiceLogoPreview.src = dataUrl;
    elements.invoiceLogoPreview.classList.toggle("hidden", !dataUrl);
    applyWebsiteLogo(dataUrl);
  };
  reader.readAsDataURL(file);
}

async function loadCustomBrandingPreset() {
  try {
    const response = await fetch(API_BASE + "/branding/baukometra-logo.svg");
    if (!response.ok) {
      throw new Error(`HTTP ${response.status}`);
    }

    const svg = await response.text();
    const logoDataUrl = `data:image/svg+xml;charset=utf-8,${encodeURIComponent(svg)}`;

    document.querySelector("#platformName").value = "BauPass";
    document.querySelector("#operatorName").value = "Baukometra";
    document.querySelector("#invoicePrimaryColor").value = "#0f4c5c";
    document.querySelector("#invoiceAccentColor").value = "#e36414";

    elements.invoiceLogoData.value = logoDataUrl;
    elements.invoiceLogoPreview.src = logoDataUrl;
    elements.invoiceLogoPreview.classList.remove("hidden");
    applyWebsiteLogo(logoDataUrl);

    showToast(uiT("alertBrandingLoaded"));
  } catch (error) {
    showToast(uiT("alertBrandingLoadFailed").replace("{error}", error.message));
  }
}

