function applyDeepLinkViewFromUrl() {
  if (!token) {
    return;
  }
  const params = new URLSearchParams(window.location.search);
  let view = params.get("view");
  if (!view) {
    const hash = (window.location.hash || "").replace(/^#/, "").trim();
    const hashViews = {
      workers: "workers",
      access: "access",
      leave: "leave",
      admin: "admin",
      devices: "devices",
      invoices: "invoices",
      documents: "documents",
      badge: "badge",
      dashboard: "dashboard",
      einsatzplan: "deployment-plan",
      "deployment-plan": "deployment-plan",
    };
    if (hash && hashViews[hash]) {
      view = hashViews[hash];
    }
  }
  if (params.get("einsatzplan") === "1" || view === "deployment-plan") {
    requestEinsatzplanEditor();
    return;
  }
  const upgradePlan = String(params.get("upgrade_plan") || "").trim().toLowerCase();
  if (params.get("billing") === "1") {
    pendingFocusBilling = true;
    if (upgradePlan) pendingHubUpgradePlan = upgradePlan;
  }
  if (!view) {
    if (pendingFocusBilling) {
      const billingViews = getAllowedViewsForRole(getEffectiveUiRole());
      if (billingViews.includes("invoices")) {
        setView("invoices");
      } else if (upgradePlan) {
        void tryHubUpgradeCheckout(upgradePlan);
      }
    }
    return;
  }
  const allowed = getAllowedViewsForRole(getEffectiveUiRole());
  if (allowed.includes(view)) {
    setView(view);
  } else if (upgradePlan) {
    void tryHubUpgradeCheckout(upgradePlan);
  }
}

window.addEventListener("message", (event) => {
  if (!event?.data || event.origin !== window.location.origin) {
    return;
  }
  if (event.data.type === "baupass-require-login") {
    refreshAll();
    showToast(
      uiT("deploymentPlanLoginRequired") || "Bitte zuerst anmelden.",
      "error",
      8000,
    );
    focusLoginInput({ force: true });
    return;
  }
  if (event.data.type === "baupass-upgrade-checkout") {
    if (!token) {
      refreshAll();
      showToast(
        uiT("deploymentPlanLoginRequired") || "Bitte zuerst anmelden.",
        "error",
        8000,
      );
      focusLoginInput({ force: true });
      return;
    }
    void tryHubUpgradeCheckout(event.data.plan);
    return;
  }
  if (event.data.type !== "baupass-navigate") {
    return;
  }
  if (!token) {
    refreshAll();
    showToast(
      uiT("deploymentPlanLoginRequired") || "Bitte zuerst anmelden.",
      "error",
      8000,
    );
    focusLoginInput({ force: true });
    return;
  }
  const view = String(event.data.view || "").trim();
  const allowedViews = getAllowedViewsForRole(getEffectiveUiRole());
  const upgradePlan = String(event.data.hubUpgradePlan || "").trim().toLowerCase();
  if (event.data.focusBilling) {
    pendingFocusBilling = true;
    if (upgradePlan) pendingHubUpgradePlan = upgradePlan;
  }
  if (event.data.focusCompanies) {
    pendingFocusCompanies = true;
  }
  if (view === "deployment-plan" || event.data.focusEinsatzplan) {
    requestEinsatzplanEditor({
      workerId: event.data.workerId,
      workerName: event.data.workerName,
    });
    return;
  }
  if (view && allowedViews.includes(view)) {
    if (view === "ai-assistant") {
      pendingEnterpriseEmbedItemId = "ai-assistant";
    }
    if (view === "admin-v2" && event.data.focusEinsatzplan) {
      pendingAdminV2EinsatzplanFocus = true;
      pendingEnterpriseEmbedItemId = "admin-v2";
    }
    if (event.data.companyId) {
      const cid = String(event.data.companyId).trim();
      if (cid && getEffectiveUiRole() === "superadmin") {
        superadminUiPreviewCompanyId = cid;
        try {
          localStorage.setItem("baupass-preview-company-id", cid);
        } catch {
          // ignore
        }
      }
    }
    setView(view);
    if (view === "admin-v2" && event.data.focusEinsatzplan) {
      scheduleAdminV2EinsatzplanFocus();
    }
    return;
  }
  if (upgradePlan && String(getEffectiveUiRole() || "").toLowerCase() === "company-admin") {
    void tryHubUpgradeCheckout(upgradePlan);
    return;
  }
  if (view === "deployment-plan" && !allowedViews.includes(view)) {
    showToast(
      uiT("deploymentPlanLockedToast") || "Einsatzplan ist in Ihrem Paket nicht freigeschaltet (ab Professional).",
      "error",
      7000,
    );
    return;
  }
  if (event.data.url && typeof event.data.url === "string") {
    window.open(event.data.url, "_blank", "noopener,noreferrer");
  }
});

