const invoiceRetryBulkSendBtn = document.querySelector("#invoiceRetryBulkSendBtn");
if (invoiceRetryBulkSendBtn) {
  invoiceRetryBulkSendBtn.addEventListener("click", async () => {
    const selectedIds = Array.isArray(state.invoiceRetrySelectedIds) ? state.invoiceRetrySelectedIds : [];
    if (!selectedIds.length) {
      showToast(uiT("alertSelectInvoiceForRetry"));
      return;
    }
    if (!(await showConfirmDialog(uiT("confirmBulkRetrySelected").replace("{count}", selectedIds.length)))) {
      return;
    }
    try {
      const payload = await apiRequest(`${API_BASE}/api/invoices/retry-send-bulk`, {
        method: "POST",
        body: { invoiceIds: selectedIds }
      });
      if (payload?.approvalRequested) {
        showToast(uiT("alertDeadLetterResolveApprovalRequested").replace("{id}", payload.approvalId), "info", 3600);
      } else {
        const summary = payload?.summary || {};
        showToast(uiT("alertBulkRetryDone").replace("{sent}", summary.sent || 0).replace("{failed}", summary.failed || 0).replace("{skipped}", summary.skipped || 0), "success", 3600);
      }
      state.invoiceRetrySelectedIds = [];
      await loadAndRenderInvoices();
      await loadAllData();
      refreshAll();
    } catch (error) {
      showToast(uiT("alertBulkRetryFailed").replace("{error}", error.message), "error", 3600);
    }
  });
}

