/**
 * Helper: Download blob as file
 */
function downloadBlob(blob, filename) {
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

/**
 * Show alert message (existing function wrapper)
 */
function showAlert(key, vars = {}) {
  const normalizedKey = String(key || "").toLowerCase();
  const msg = UI_TRANSLATIONS[getCurrentLang()]?.[key] || key;
  let text = msg;
  for (const [k, v] of Object.entries(vars)) {
    text = text.replace(`{${k}}`, String(v));
  }

  const isErrorLike = /failed|error|invalid|forbidden|missing|required|denied|locked|expired|conflict|unavailable/.test(normalizedKey);
  const isSuccessLike = /success|saved|sent|done|enabled|disabled|updated|copied|confirmed|activated|created|loaded/.test(normalizedKey);
  const type = isErrorLike ? "error" : (isSuccessLike ? "success" : "info");
  const duration = type === "error" ? 4200 : (type === "success" ? 2800 : 3200);
  showToast(text, type, duration);
}

let activeConfirmCloser = null;

function showToast(message, type = "info", timeout = 2600) {
  const text = String(message || "").trim();
  if (!text) return;
  const normalizedType = ["info", "success", "error"].includes(String(type || "").toLowerCase())
    ? String(type).toLowerCase()
    : "info";
  let el = document.getElementById("appToast");
  if (!el) {
    el = document.createElement("div");
    el.id = "appToast";
    el.className = "app-toast";
    document.body.appendChild(el);
  }
  el.setAttribute("role", normalizedType === "error" ? "alert" : "status");
  el.setAttribute("aria-live", normalizedType === "error" ? "assertive" : "polite");
  el.setAttribute("aria-atomic", "true");
  el.textContent = text;
  el.className = `app-toast app-toast-${normalizedType}`;
  el.classList.add("is-visible");
  const existingTimer = Number(el.dataset.timerId || 0);
  if (existingTimer) {
    window.clearTimeout(existingTimer);
  }
  const timerId = window.setTimeout(() => {
    el.classList.remove("is-visible");
  }, Math.max(1200, Number(timeout) || 2600));
  el.dataset.timerId = String(timerId);
}

function showConfirmDialog(message) {
  return new Promise((resolve) => {
    if (typeof activeConfirmCloser === "function") {
      activeConfirmCloser(false);
    }

    const previouslyFocused = document.activeElement;
    const messageId = `app-confirm-message-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
    const overlay = document.createElement("div");
    overlay.className = "worker-app-qr-overlay app-confirm-overlay";
    overlay.innerHTML = `
      <div class="worker-app-qr-card app-confirm-card">
        <p class="app-confirm-message" id="${messageId}">${escapeHtml(String(message || ""))}</p>
        <div class="button-row">
          <button type="button" class="ghost-button" data-confirm-cancel>${escapeHtml(uiT("btnBulkCancel"))}</button>
          <button type="button" class="primary-button" data-confirm-accept>${escapeHtml(uiT("btnConfirmOk"))}</button>
        </div>
      </div>
    `;

    const cancelButton = overlay.querySelector("[data-confirm-cancel]");
    const acceptButton = overlay.querySelector("[data-confirm-accept]");
    const focusables = [cancelButton, acceptButton].filter(Boolean);
    const panel = overlay.querySelector(".app-confirm-card");
    if (panel) {
      panel.setAttribute("role", "dialog");
      panel.setAttribute("aria-modal", "true");
      panel.setAttribute("aria-labelledby", messageId);
      panel.setAttribute("tabindex", "-1");
    }

    let closed = false;
    const close = (result) => {
      if (closed) return;
      closed = true;
      if (activeConfirmCloser === close) {
        activeConfirmCloser = null;
      }
      document.removeEventListener("keydown", onKeyDown);
      overlay.remove();
      if (previouslyFocused && document.contains(previouslyFocused) && typeof previouslyFocused.focus === "function") {
        try { previouslyFocused.focus(); } catch { /* ignore focus failures */ }
      }
      resolve(Boolean(result));
    };

    const onKeyDown = (event) => {
      if (closed) return;
      if (event.key === "Escape") {
        event.preventDefault();
        close(false);
        return;
      }
      if (event.key === "Enter") {
        event.preventDefault();
        close(true);
        return;
      }
      if (event.key === "Tab" && focusables.length) {
        const currentIndex = focusables.indexOf(document.activeElement);
        if (event.shiftKey) {
          event.preventDefault();
          const prevIndex = currentIndex <= 0 ? focusables.length - 1 : currentIndex - 1;
          focusables[prevIndex].focus();
        } else {
          event.preventDefault();
          const nextIndex = currentIndex === -1 || currentIndex >= focusables.length - 1 ? 0 : currentIndex + 1;
          focusables[nextIndex].focus();
        }
      }
    };

    cancelButton?.addEventListener("click", () => close(false), { once: true });
    acceptButton?.addEventListener("click", () => close(true), { once: true });
    overlay.addEventListener("click", (event) => {
      if (event.target === overlay) close(false);
    });
    activeConfirmCloser = close;
    document.body.appendChild(overlay);
    document.addEventListener("keydown", onKeyDown);
    if (acceptButton && typeof acceptButton.focus === "function") {
      acceptButton.focus();
    } else if (panel && typeof panel.focus === "function") {
      panel.focus();
    }
  });
}

/**
 * Get current UI language
 */
function getCurrentLang() {
  try {
    return window.localStorage.getItem(UI_LANG_STORAGE_KEY) || "de";
  } catch {
    return "de";
  }
}

function warnBrowserZoom() {
  try {
    const scale = window.visualViewport?.scale || 1;
    if (scale > 1.05) {
      showToast(
        `Browser-Zoom liegt bei etwa ${Math.round(scale * 100)} %. Mit Strg+0 auf 100 % zurÃžcksetzen.`,
        "info",
        7000
      );
    }
  } catch {
    // no-op
  }
}

function warnStaleControlAssets() {
  try {
    const cssHref = document.querySelector('link[rel="stylesheet"][href*="styles.css"]')?.getAttribute("href") || "";
    if (cssHref && !cssHref.includes("20260524h")) {
      showToast(
        "Alte OberflÃĪche im Browser-Cache. Bitte Strg+F5 drÃžcken â auf dem Server muss zuerst das neue Docker-Image deployed werden.",
        "warning",
        9000
      );
    }
  } catch {
    // no-op
  }
}

